export const AhorrosProvider = ({ children }) => {
    const [cuentas, setCuentas] = useState([]);
    const [movimientos, setMovimientos] = useState([]);

    useEffect(() => {
        const loadData = async () => {
            const cData = await api.get('cuentas_ahorro');
            const mData = await api.get('movimientos_ahorro');

            if (cData && Array.isArray(cData) && cData.length > 0) {
                setCuentas(cData);
            } else {
                setCuentas(defaultCuentas);
                await api.save('cuentas_ahorro', defaultCuentas);
            }

            if (mData && Array.isArray(mData) && mData.length > 0) {
                setMovimientos(mData);
            } else {
                setMovimientos(defaultMovimientos);
                await api.save('movimientos_ahorro', defaultMovimientos);
            }
        };
        loadData();
    }, []);

    useEffect(() => {
        if (cuentas.length > 0) api.save('cuentas_ahorro', cuentas);
        if (movimientos.length > 0) api.save('movimientos_ahorro', movimientos);
    }, [cuentas, movimientos]);

    const abrirCuenta = (datos) => {
        const nueva = {
            ...datos,
            id: Date.now().toString(),
            numero: `${datos.tipo.substring(0, 3).toUpperCase()}-${datos.socioId}-${Math.floor(Math.random() * 1000)}`,
            balance: Number(datos.montoInicial) || 0,
            estado: 'Activa',
            fechaApertura: new Date().toISOString()
        };
        setCuentas(prev => [...prev, nueva]);

        if (Number(datos.montoInicial) > 0) {
            registrarMovimiento(nueva.id, 'Deposito', datos.montoInicial, 'Apertura de cuenta');
        }
        return nueva;
    };

    const registrarMovimiento = (cuentaId, tipo, monto, nota) => {
        const nuevoM = {
            id: Date.now().toString(),
            cuentaId,
            tipo,
            monto: Number(monto),
            fecha: new Date().toISOString(),
            nota
        };
        setMovimientos(prev => [...prev, nuevoM]);

        setCuentas(prev => prev.map(c => {
            if (c.id === cuentaId) {
                const nuevoBalance = tipo === 'Deposito' ? c.balance + Number(monto) : c.balance - Number(monto);
                return { ...c, balance: nuevoBalance };
            }
            return c;
        }));
    };

    const calcularIntereses = (cuentaId = null) => {
        if (cuentaId) {
            const cuenta = cuentas.find(c => c.id === cuentaId);
            if (!cuenta || cuenta.tasa <= 0) return 0;
            const intereses = (cuenta.balance * (cuenta.tasa / 100)) / 12;
            return Math.round(intereses * 100) / 100;
        } else {
            // Proceso masivo
            let total = 0;
            cuentas.forEach(c => {
                if (c.tasa > 0) {
                    const int = (c.balance * (c.tasa / 100)) / 12;
                    total += Math.round(int * 100) / 100;
                }
            });
            return total;
        }
    };

    return (
        <AhorrosContext.Provider value={{
            cuentas,
            movimientos,
            abrirCuenta,
            registrarMovimiento,
            calcularIntereses
        }}>
            {children}
        </AhorrosContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { api } from '../utils/api';

const AuthContext = createContext(null);

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [empresa, setEmpresa] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [token, setToken] = useState(null);
    const initialized = useRef(false);

    useEffect(() => {
        // Only run once on mount
        if (initialized.current) return;
        initialized.current = true;

        const savedToken = localStorage.getItem('iubel_token');

        if (!savedToken) {
            // No token stored → go straight to login
            setIsLoading(false);
            return;
        }

        // Token exists → validate it with a 5-second timeout
        const controller = new AbortController();
        const timeout = setTimeout(() => {
            controller.abort();
        }, 5000);

        const validateToken = async () => {
            try {
                const resp = await fetch('http://localhost:3001/api/auth/me', {
                    headers: {
                        'Authorization': `Bearer ${savedToken}`,
                        'Content-Type': 'application/json'
                    },
                    signal: controller.signal
                });

                if (resp.ok) {
                    const data = await resp.json();
                    setToken(savedToken);
                    setUser(data.user);
                    setEmpresa(data.empresa);
                } else {
                    // Token invalid / expired
                    localStorage.removeItem('iubel_token');
                }
            } catch {
                // Network error or timeout → clear token to force re-login
                localStorage.removeItem('iubel_token');
            } finally {
                clearTimeout(timeout);
                setIsLoading(false);
            }
        };

        validateToken();

        return () => {
            controller.abort();
            clearTimeout(timeout);
        };
    }, []);

    const clearSession = () => {
        localStorage.removeItem('iubel_token');
        // Wipe any residual cached data so next login starts fresh
        const keysToRemove = Object.keys(localStorage).filter(k => k !== 'iubel_token');
        keysToRemove.forEach(k => localStorage.removeItem(k));
        setToken(null);
        setUser(null);
        setEmpresa(null);
    };

    const login = async (empresaNombre, email, password) => {
        const result = await api.authPost('/api/auth/login', { empresaNombre, email, password });
        if (!result.ok) {
            throw new Error(result.data.error || 'Error de autenticación');
        }
        const { token: newToken, user: newUser, empresa: newEmpresa } = result.data;
        localStorage.setItem('iubel_token', newToken);
        setToken(newToken);
        setUser(newUser);
        setEmpresa(newEmpresa);
        return result.data;
    };

    const register = async (formData) => {
        const result = await api.authPost('/api/auth/register', formData);
        if (!result.ok) {
            throw new Error(result.data.error || 'Error en el registro');
        }
        const { token: newToken, user: newUser, empresa: newEmpresa } = result.data;
        localStorage.setItem('iubel_token', newToken);
        setToken(newToken);
        setUser(newUser);
        setEmpresa(newEmpresa);
        return result.data;
    };

    const logout = () => {
        clearSession();
    };

    return (
        <AuthContext.Provider value={{
            user,
            empresa,
            token,
            isAuthenticated: !!token && !!user,
            isLoading,
            login,
            register,
            logout
        }}>
            {children}
        </AuthContext.Provider>
    );
};

