import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../utils/api';

const NCFContext = createContext();

export const useNCF = () => useContext(NCFContext);

export const NCFProvider = ({ children }) => {
    const [rangos, setRangos] = useState([]);

    useEffect(() => {
        const loadNCF = async () => {
            const data = await api.get('ncf_rangos');
            if (data && Array.isArray(data)) {
                setRangos(data);
            }
        };
        loadNCF();
    }, []);

    useEffect(() => {
        if (rangos.length > 0) {
            api.save('ncf_rangos', rangos);
        }
    }, [rangos]);

    const agregarRango = (nuevoRango) => {
        const rangoFull = {
            ...nuevoRango,
            id: Date.now().toString(),
            actual: nuevoRango.inicio,
            activo: true,
            fechaRegistro: new Date().toISOString()
        };
        // Desactivar otros del mismo tipo
        setRangos(prev => [
            ...prev.map(r => r.tipo === nuevoRango.tipo ? { ...r, activo: false } : r),
            rangoFull
        ]);
    };

    const eliminarRango = (id) => {
        setRangos(prev => prev.filter(r => r.id !== id));
    };

    const generarSiguienteNCF = (tipo) => {
        const rangoIdx = rangos.findIndex(r => r.tipo === tipo && r.activo);
        if (rangoIdx === -1) {
            throw new Error(`No hay un rango activo configurado para el tipo ${tipo}.`);
        }

        const rango = rangos[rangoIdx];
        if (Number(rango.actual) > Number(rango.fin)) {
            throw new Error(`Se ha agotado el rango de comprobantes para ${tipo}. Por favor registre uno nuevo.`);
        }

        const ncfFormateado = `${tipo}${rango.actual.toString().padStart(8, '0')}`;

        // Incrementar actual
        setRangos(prev => prev.map((r, i) =>
            i === rangoIdx ? { ...r, actual: Number(r.actual) + 1 } : r
        ));

        return ncfFormateado;
    };

    return (
        <NCFContext.Provider value={{
            rangos,
            agregarRango,
            eliminarRango,
            generarSiguienteNCF
        }}>
            {children}
        </NCFContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../utils/api';
import { useContabilidad } from './ContabilidadContext';

const NominaContext = createContext();

export const useNomina = () => useContext(NominaContext);

// Constantes de Ley RD (Ajustables según DGII/TSS)
const TSS_AFP_EMP = 0.0287; // 2.87%
const TSS_SFS_EMP = 0.0304; // 3.04%
const EXENCION_ANUAL = 416220.00; // Hasta 34,685 mens aprox.

export const NominaProvider = ({ children }) => {
    const { registrarAsiento } = useContabilidad();
    const [empleados, setEmpleados] = useState([]);
    const [nominasProcesadas, setNominasProcesadas] = useState([]);

    // Cargar datos del servidor al iniciar
    useEffect(() => {
        const loadNominaData = async () => {
            const dataEmp = await api.get('empleados');
            if (dataEmp && Array.isArray(dataEmp) && dataEmp.length > 0) {
                setEmpleados(dataEmp);
            } else {
                const defaultEmps = [
                    { id: '1', nombre: 'Uriel F J', cargo: 'Director Ejecutivo', sueldo: 120000, cedula: '001-0000000-1', activo: true },
                    { id: '2', nombre: 'Carmen Jimenez', cargo: 'Gerente Financiera', sueldo: 85000, cedula: '001-0000000-2', activo: true }
                ];
                setEmpleados(defaultEmps);
                await api.save('empleados', defaultEmps);
            }

            const dataNom = await api.get('nominas_historial');
            if (dataNom && Array.isArray(dataNom)) {
                setNominasProcesadas(dataNom);
            }
        };
        loadNominaData();
    }, []);

    // Sincronizar con el servidor y localStorage al cambiar
    useEffect(() => {
        if (empleados.length > 0) api.save('empleados', empleados);
    }, [empleados]);

    useEffect(() => {
        if (nominasProcesadas.length > 0) api.save('nominas_historial', nominasProcesadas);
    }, [nominasProcesadas]);

    // Función para calcular ISR (Escala RD)
    const calcularISR = (sueldoNetoTSS) => {
        const anual = sueldoNetoTSS * 12;
        let impuestoAnual = 0;

        if (anual <= 416220.00) {
            impuestoAnual = 0;
        } else if (anual <= 624329.00) {
            impuestoAnual = (anual - 416220.01) * 0.15;
        } else if (anual <= 867123.00) {
            impuestoAnual = 31216.00 + ((anual - 624329.01) * 0.20);
        } else {
            impuestoAnual = 79776.00 + ((anual - 867123.01) * 0.25);
        }

        return impuestoAnual / 12;
    };

    const calcularDetalleNomina = (empleado) => {
        const afp = empleado.sueldo * TSS_AFP_EMP;
        const sfs = empleado.sueldo * TSS_SFS_EMP;
        const sueldoNetoTSS = empleado.sueldo - afp - sfs;
        const isr = calcularISR(sueldoNetoTSS);
        const deducciones = afp + sfs + isr;
        const sueldoNeto = empleado.sueldo - deducciones;

        return {
            sueldoBruto: empleado.sueldo,
            afp,
            sfs,
            isr,
            deducciones,
            sueldoNeto
        };
    };

    const procesarNominaMes = (mes) => {
        const detalle = empleados.filter(e => e.activo).map(e => ({
            ...e,
            calculos: calcularDetalleNomina(e)
        }));

        const totalSueldos = detalle.reduce((acc, d) => acc + d.sueldo, 0);
        const totalNeto = detalle.reduce((acc, d) => acc + d.calculos.sueldoNeto, 0);
        const totalAFP = detalle.reduce((acc, d) => acc + d.calculos.afp, 0);
        const totalSFS = detalle.reduce((acc, d) => acc + d.calculos.sfs, 0);
        const totalISR = detalle.reduce((acc, d) => acc + d.calculos.isr, 0);

        const nuevaNomina = {
            id: Date.now().toString(),
            mes,
            fecha: new Date().toISOString(),
            detalle,
            totales: { totalSueldos, totalNeto, totalAFP, totalSFS, totalISR }
        };

        setNominasProcesadas(prev => [...prev, nuevaNomina]);

        // Asiento Contable Automático
        const detallesContables = [
            { cuentaId: '6101', cuentaCodigo: '6101', debito: totalSueldos, credito: 0, descripcion: 'Gasto de Sueldos y Salarios' },
            { cuentaId: '2105', cuentaCodigo: '2105', debito: 0, credito: totalAFP + totalSFS, descripcion: 'Retenciones TSS por Pagar' },
            { cuentaId: '2106', cuentaCodigo: '2106', debito: 0, credito: totalISR, descripcion: 'Retenciones ISR por Pagar' },
            { cuentaId: '110101', cuentaCodigo: '110101', debito: 0, credito: totalNeto, descripcion: 'Pago de Nómina (Banco)' }
        ];

        registrarAsiento(
            `Pago de Nómina - ${mes}`,
            detallesContables,
            new Date().toISOString(),
            'Nómina',
            `NOM-${nuevaNomina.id}`
        );

        return nuevaNomina;
    };

    const agregarEmpleado = (empleado) => {
        setEmpleados(prev => [...prev, { ...empleado, id: Date.now().toString(), activo: true }]);
    };

    const eliminarEmpleado = (id) => {
        setEmpleados(empleados.filter(e => e.id !== id));
    };

    const eliminarNomina = (id) => {
        setNominasProcesadas(nominasProcesadas.filter(n => n.id !== id));
    };

    return (
        <NominaContext.Provider value={{
            empleados,
            nominasProcesadas,
            procesarNominaMes,
            agregarEmpleado,
            eliminarEmpleado,
            eliminarNomina,
            calcularDetalleNomina
        }}>
            {children}
        </NominaContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../utils/api';
import { useContabilidad } from './ContabilidadContext';
import { useNCF } from './NCFContext';

const NotasContext = createContext();
export const useNotas = () => useContext(NotasContext);

export const NotasProvider = ({ children }) => {
    const { registrarAsiento } = useContabilidad();
    const { generarSiguienteNCF } = useNCF();

    const [notas, setNotas] = useState([]);

    // Cargar datos del servidor al iniciar
    useEffect(() => {
        const loadNotas = async () => {
            const data = await api.get('notas');
            if (data && Array.isArray(data)) {
                setNotas(data);
            }
        };
        loadNotas();
    }, []);

    // Sincronizar con el servidor al cambiar
    useEffect(() => {
        if (notas.length > 0) {
            api.save('notas', notas);
        }
    }, [notas]);

    const registrarNota = (nuevaNota) => {
        // Generar NCF automáticamente si no viene uno manual
        let ncfFinal = nuevaNota.ncf;
        const tipoB = nuevaNota.tipoNota === 'credito' ? 'B04' : 'B03';

        try {
            if (!ncfFinal) {
                ncfFinal = generarSiguienteNCF(tipoB);
            }
        } catch (e) {
            console.warn("No se pudo generar NCF automático:", e.message);
            if (!ncfFinal) {
                alert(`Error: ${e.message}. Asegúrese de configurar un rango para ${tipoB}.`);
                return;
            }
        }

        const notaFull = {
            ...nuevaNota,
            id: Date.now().toString(),
            ncf: ncfFinal,
            fecha: new Date().toISOString(),
            estado: 'Aplicada'
        };

        // Asiento Contable
        const detalles = [
            { cuentaId: nuevaNota.cuentaId, debito: nuevaNota.tipoNota === 'debito' ? nuevaNota.monto : 0, credito: nuevaNota.tipoNota === 'credito' ? nuevaNota.monto : 0 },
            { cuentaId: nuevaNota.contraCuentaId || '110101', debito: nuevaNota.tipoNota === 'credito' ? nuevaNota.monto : 0, credito: nuevaNota.tipoNota === 'debito' ? nuevaNota.monto : 0 }
        ];

        registrarAsiento(
            `Nota de ${nuevaNota.tipoNota === 'credito' ? 'Crédito' : 'Débito'}: ${ncfFinal}`,
            detalles,
            new Date().toISOString(),
            'Notas CD',
            `NT-${notaFull.id}`
        );

        setNotas(prev => [...prev, notaFull]);
        return notaFull;
    };

    return (
        <NotasContext.Provider value={{
            notas,
            registrarNota
        }}>
            {children}
        </NotasContext.Provider>
    );
};

