        if (sistema === 'Frances') {
            // Cuota Fija
            const cuota = (monto * tasaMensual) / (1 - Math.pow(1 + tasaMensual, -meses));
            for (let i = 1; i <= meses; i++) {
                const interes = balance * tasaMensual;
                const capital = cuota - interes;
                balance -= capital;
                tabla.push({
                    mes: i,
                    cuota: Math.round(cuota * 100) / 100,
                    interes: Math.round(interes * 100) / 100,
                    capital: Math.round(capital * 100) / 100,
                    balance: Math.max(0, Math.round(balance * 100) / 100)
                });
            }
        } else {
            // Alemán: Capital Fijo (Cuota variable decreciente)
            const capitalFijo = monto / meses;
            for (let i = 1; i <= meses; i++) {
                const interes = balance * tasaMensual;
                const cuota = capitalFijo + interes;
                balance -= capitalFijo;
                tabla.push({
                    mes: i,
                    cuota: Math.round(cuota * 100) / 100,
                    interes: Math.round(interes * 100) / 100,
                    capital: Math.round(capitalFijo * 100) / 100,
                    balance: Math.max(0, Math.round(balance * 100) / 100)
                });
            }
        }

        return {
            tabla,
            cuotaPromedio: tabla.reduce((acc, curr) => acc + curr.cuota, 0) / meses,
            totalInteres: tabla.reduce((acc, curr) => acc + curr.interes, 0)
        };
    };

    const registrarPrestamo = (datos) => {
        const { tabla, cuotaPromedio } = generarAmortizacion(
            Number(datos.monto),
            Number(datos.tasa),
            Number(datos.plazo),
            datos.sistema || 'Frances'
        );
        const nuevo = {
            ...datos,
            id: `PRE-${Date.now().toString().substring(7)}`,
            cuota: Math.round(cuotaPromedio * 100) / 100,
            tabla,
            balance: Number(datos.monto),
            estado: 'Vigente',
            fechaDesembolso: new Date().toISOString()
        };
        setPrestamos(prev => [...prev, nuevo]);
        return nuevo;
    };

    return (
        <PrestamosContext.Provider value={{
            prestamos,
            registrarPrestamo,
            generarAmortizacion
        }}>
            {children}
        </PrestamosContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../utils/api';
import { useCuentas } from './CuentasContext';

const PresupuestoContext = createContext();

export const usePresupuesto = () => useContext(PresupuestoContext);

export const PresupuestoProvider = ({ children }) => {
    // Estructura: { [periodo]: { [cuentaId]: monto } }
    // Ejemplo: { '2024-03': { '4101': 500000 } }
    const [presupuestos, setPresupuestos] = useState({});

    useEffect(() => {
        const loadPresupuestos = async () => {
            const data = await api.get('presupuestos');
            if (data && !Array.isArray(data) && Object.keys(data).length > 0) {
                setPresupuestos(data);
            }
        };
        loadPresupuestos();
    }, []);

    useEffect(() => {
        api.save('presupuestos', presupuestos);
    }, [presupuestos]);

    const guardarPresupuesto = (periodo, cuentaId, monto) => {
        setPresupuestos(prev => ({
            ...prev,
            [periodo]: {
                ...(prev[periodo] || {}),
                [cuentaId]: parseFloat(monto) || 0
            }
        }));
    };

    const obtenerPresupuesto = (periodo, cuentaId) => {
        return presupuestos[periodo]?.[cuentaId] || 0;
    };

    const obtenerPresupuestoPeriodo = (periodo) => {
        return presupuestos[periodo] || {};
    };

    return (
        <PresupuestoContext.Provider value={{
            presupuestos,
            guardarPresupuesto,
            obtenerPresupuesto,
            obtenerPresupuestoPeriodo
        }}>
            {children}
        </PresupuestoContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../utils/api';

const RecurrentesContext = createContext();
export const useRecurrentes = () => useContext(RecurrentesContext);

export const RecurrentesProvider = ({ children }) => {
    const [plantillas, setPlantillas] = useState([]);

    useEffect(() => {
        const loadRecurrentes = async () => {
            const data = await api.get('recurrentes');
            if (data && Array.isArray(data)) {
                setPlantillas(data);
            }
        };
        loadRecurrentes();
    }, []);

    useEffect(() => {
        if (plantillas.length > 0) {
            api.save('recurrentes', plantillas);
        }
    }, [plantillas]);

    const crearPlantilla = (p) => {
        setPlantillas(prev => [...prev, {
            ...p,
            id: Date.now().toString(),
            fechaCreacion: new Date().toISOString(),
            activa: true,
            vecesEjecutada: 0
        }]);
    };

    const togglePlantilla = (id) => {
        setPlantillas(prev => prev.map(p => p.id === id ? { ...p, activa: !p.activa } : p));
    };

    const eliminarPlantilla = (id) => {
        setPlantillas(prev => prev.filter(p => p.id !== id));
    };

    const marcarEjecucion = (id) => {
        setPlantillas(prev => prev.map(p => p.id === id
            ? { ...p, vecesEjecutada: p.vecesEjecutada + 1, ultimaEjecucion: new Date().toISOString() }
            : p
        ));
    };

    return (
        <RecurrentesContext.Provider value={{ plantillas, crearPlantilla, togglePlantilla, eliminarPlantilla, marcarEjecucion }}>
            {children}
        </RecurrentesContext.Provider>
    );
