                                {panel.datos.map(([label, val], j) => (
                                    <div key={j} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid var(--border)' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>{label}</span>
                                        <span style={{ fontWeight: 700, color: 'var(--primary)' }}>{val}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {tab === 2 && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                    <div className="card">
                        <h3 style={{ fontWeight: 700, marginBottom: '1.5rem' }}>👩‍💼 Equipo de Trabajo</h3>
                        {[
                            ['Total Empleados', indicadores.empleo.totalEmpleados],
                            ['Mujeres', `${indicadores.empleo.empleadosFemeninos} (${((indicadores.empleo.empleadosFemeninos / indicadores.empleo.totalEmpleados) * 100).toFixed(0)}%)`],
                            ['Hombres', `${indicadores.empleo.empleadosMasculinos} (${((indicadores.empleo.empleadosMasculinos / indicadores.empleo.totalEmpleados) * 100).toFixed(0)}%)`],
                            ['Nuevos Empleos Generados', `+${indicadores.empleo.nuevosEmpleos}`],
                            ['Salario Promedio Mensual', f(indicadores.empleo.salarioPromedio)],
                            ['Horas de Capacitación', `${indicadores.empleo.capacitacionesHoras}h`],
                        ].map(([l, v], j) => (
                            <div key={j} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.75rem 0', borderBottom: '1px solid var(--border)' }}>
                                <span style={{ color: 'var(--text-muted)' }}>{l}</span>
                                <span style={{ fontWeight: 700, color: 'var(--primary)' }}>{v}</span>
                            </div>
                        ))}
                    </div>
                    <div className="card glass">
                        <h3 style={{ fontWeight: 700, marginBottom: '1.5rem' }}>Empleos por Género</h3>
                        <div style={{ height: 200, position: 'relative', minHeight: '200px' }}>
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart><Pie data={empleoData} cx="50%" cy="50%" outerRadius={80} dataKey="value" isAnimationActive={false}>
                                    {empleoData.map((_, i) => <Cell key={i} fill={['#8b5cf6', '#2563eb'][i]} />)}
                                </Pie><Tooltip /></PieChart>
                            </ResponsiveContainer>
                        </div>
                        <div style={{ display: 'flex', justifyContent: 'center', gap: '2rem', marginTop: '1rem' }}>
                            {empleoData.map((d, i) => <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem' }}><div style={{ width: 10, height: 10, borderRadius: '50%', background: ['#8b5cf6', '#2563eb'][i] }} />{d.name}: <strong>{d.value}</strong></div>)}
                        </div>
                    </div>
                </div>
            )}

            {tab === 3 && (
                <div style={{ display: 'grid', gap: '1.25rem' }}>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.25rem', marginBottom: '1rem' }}>
                        {[
                            ['🌍 Beneficiarios Directos', fNum(indicadores.impactoSocial.beneficiariosDirectos), 'personas impactadas'],
                            ['🏘️ Proyectos Comunitarios', indicadores.impactoSocial.proyectosComunitarios, 'proyectos activos'],
                            ['🎓 Becas Otorgadas', indicadores.impactoSocial.becariosApoyados, 'estudiantes apoyados'],
                        ].map(([lab, val, sub], i) => (
                            <div key={i} className="card glass" style={{ textAlign: 'center', padding: '1.5rem' }}>
                                <div style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--primary)', marginBottom: '0.25rem' }}>{val}</div>
                                <div style={{ fontWeight: 700, marginBottom: '0.15rem' }}>{lab}</div>
                                <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{sub}</div>
                            </div>
                        ))}
                    </div>
                    <div className="card">
                        <h3 style={{ fontWeight: 700, marginBottom: '1.25rem' }}>📅 Actividades de Impacto Social</h3>
                        <div style={{ display: 'grid', gap: '0.75rem' }}>
                            {indicadores.impactoSocial.actividades.map((act, i) => (
                                <div key={i} style={{ display: 'flex', gap: '1rem', alignItems: 'center', padding: '1rem', background: 'var(--background)', borderRadius: '10px' }}>
                                    <div style={{ width: 40, height: 40, borderRadius: '10px', background: 'rgba(139,92,246,0.1)', color: '#8b5cf6', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, flexShrink: 0 }}>{i + 1}</div>
                                    <div style={{ flex: 1 }}><div style={{ fontWeight: 600 }}>{act.nombre}</div><div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{act.fecha}</div></div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: 'var(--success)', fontWeight: 700 }}><Users size={15} /> {act.beneficiarios} beneficiarios</div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default BalanceSocial;

import React, { useState } from 'react';
import { useBancos } from '../context/BancosContext';
import { Landmark, ArrowUpCircle, ArrowDownCircle, AlertCircle, Info, CheckCircle2, Trash2 } from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const Bancos = () => {
    const { saldoLibros, saldoBancoReal, movimientosExtra, agregarMovimientoBanco, eliminarMovimientoBanco } = useBancos();
    const [monto, setMonto] = useState('');
    const [conciliado, setConciliado] = useState(false);
    const [confirmDelete, setConfirmDelete] = useState({ open: false, id: null });

    const handleAjuste = (tipo) => {
        if (!monto || isNaN(monto)) return;
        agregarMovimientoBanco({
            descripcion: tipo === 'debito' ? 'Comisión Bancaria' : 'Intereses Ganados',
            monto: parseFloat(monto),
            tipo: tipo
        });
        setMonto('');
    };

    const handleDeleteMovimiento = (id) => {
        setConfirmDelete({ open: true, id });
    };

    const confirmDeleteAction = () => {
        if (confirmDelete.id) {
            eliminarMovimientoBanco(confirmDelete.id);
            setConfirmDelete({ open: false, id: null });
        }
    };

    const formatMoney = (amount) => {
        return new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount);
    };

    return (
        <div className="animate-up">
            <div style={{ marginBottom: '2.5rem' }}>
                <h1 className="page-title" style={{ marginBottom: '0.5rem' }}>Conciliación Bancaria</h1>
                <p style={{ color: 'var(--text-muted)' }}>Compara el saldo en tus libros contables con el estado de cuenta bancario.</p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '2rem', marginBottom: '3rem' }}>
                <div className="card glass" style={{ borderLeft: '4px solid var(--primary)' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
                        <div style={{ padding: '0.75rem', background: 'var(--primary-light)', color: 'var(--primary)', borderRadius: '12px' }}>
                            <Landmark size={24} />
                        </div>
                        <div>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>Saldo según Libros</div>
                            <div style={{ fontSize: '1.75rem', fontWeight: 700, color: 'var(--text-main)' }}>{formatMoney(saldoLibros)}</div>
                        </div>
                    </div>
                    <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>Este saldo se deriva automáticamente de tus entradas de diario y facturación.</p>
                </div>

                <div className="card glass" style={{ borderLeft: `4px solid ${saldoBancoReal === saldoLibros ? 'var(--success)' : 'var(--warning)'}` }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
                        <div style={{ padding: '0.75rem', background: saldoBancoReal === saldoLibros ? 'rgba(16, 185, 129, 0.1)' : 'rgba(245, 158, 11, 0.1)', color: saldoBancoReal === saldoLibros ? 'var(--success)' : 'var(--warning)', borderRadius: '12px' }}>
                            {saldoBancoReal === saldoLibros ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
                        </div>
                        <div>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>Saldo del Banco (Ajustado)</div>
                            <div style={{ fontSize: '1.75rem', fontWeight: 700, color: 'var(--text-main)' }}>{formatMoney(saldoBancoReal)}</div>
                        </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>Diferencia: {formatMoney(saldoBancoReal - saldoLibros)}</span>
                        <button className="btn btn-secondary" onClick={() => setConciliado(true)} style={{ padding: '0.5rem 1rem', fontSize: '0.75rem' }}>
                            Marcar como Conciliado
                        </button>
                    </div>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
                <div className="card">
                    <h3 style={{ marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Info size={20} color="var(--primary)" /> Registrar Ajuste Bancario
                    </h3>
                    <div className="input-group">
                        <label className="input-label">Monto del Movimiento</label>
                        <input
                            type="number"
                            className="input-field"
                            value={monto}
                            onChange={(e) => setMonto(e.target.value)}
                            placeholder="RD$ 0.00"
                        />
                    </div>
                    <div style={{ display: 'flex', gap: '1rem' }}>
                        <button className="btn btn-secondary" style={{ flex: 1, color: 'var(--danger)' }} onClick={() => handleAjuste('debito')}>
                            <ArrowDownCircle size={18} /> Comisión / Cargo
                        </button>
                        <button className="btn btn-secondary" style={{ flex: 1, color: 'var(--success)' }} onClick={() => handleAjuste('credito')}>
                            <ArrowUpCircle size={18} /> Interés / Crédito
                        </button>
                    </div>
                </div>

                <div className="card">
                    <h3 style={{ marginBottom: '1.5rem' }}>Últimos Ajustes de Banco</h3>
                    <div style={{ overflowX: 'auto' }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead>
                                <tr style={{ borderBottom: '1px solid var(--border)', textAlign: 'left' }}>
                                    <th style={{ padding: '1rem', fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Fecha</th>
                                    <th style={{ padding: '1rem', fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Descripción</th>
                                    <th style={{ padding: '1rem', fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', textAlign: 'right' }}>Monto</th>
                                    <th style={{ padding: '1rem', fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', textAlign: 'center' }}>X</th>
                                </tr>
                            </thead>
                            <tbody>
                                {movimientosExtra.length === 0 ? (
                                    <tr>
                                        <td colSpan="4" style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)' }}>No hay ajustes registrados.</td>
                                    </tr>
                                ) : (
                                    movimientosExtra.slice().reverse().map(mov => (
                                        <tr key={mov.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                            <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{new Date(mov.fecha).toLocaleDateString()}</td>
                                            <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{mov.descripcion}</td>
                                            <td style={{ padding: '1rem', fontSize: '0.875rem', textAlign: 'right', color: mov.tipo === 'debito' ? 'var(--danger)' : 'var(--success)' }}>
                                                {mov.tipo === 'debito' ? '-' : '+'}{formatMoney(mov.monto)}
                                            </td>
                                            <td style={{ padding: '1rem', textAlign: 'center' }}>
                                                <button
                                                    className="btn"
                                                    style={{ padding: '0.25rem', color: 'var(--danger)' }}
                                                    onClick={() => handleDeleteMovimiento(mov.id)}
                                                    title="Eliminar Ajuste"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
            <ConfirmModal
                isOpen={confirmDelete.open}
                onClose={() => setConfirmDelete({ ...confirmDelete, open: false })}
                onConfirm={confirmDeleteAction}
                title="Eliminar Ajuste Bancario"
                message="¿Está seguro de que desea eliminar este ajuste? Esta acción modificará el saldo conciliado del banco."
            />
        </div>
    );
};

export default Bancos;

import React, { useState } from 'react';
import { useCaja } from '../context/CajaContext';
import {
    Banknote, Search, Printer, XCircle, CheckCircle,
    FileText, ShieldAlert, CreditCard, LayoutTemplate,
    Landmark, ArrowRightLeft, AlertTriangle, BarChart
} from 'lucide-react';

const TABS = [
    { id: 'operaciones', label: 'Operaciones', icon: LayoutTemplate },
    { id: 'pagos', label: 'Pagos', icon: CreditCard },
    { id: 'documentos', label: 'Documentos', icon: FileText },
    { id: 'bovedas', label: 'Bóvedas', icon: Landmark },
    { id: 'transacciones', label: 'Transacciones', icon: ArrowRightLeft },
    { id: 'incidencias', label: 'Incidencias', icon: ShieldAlert },
    { id: 'informes', label: 'Informes', icon: BarChart },
];

const CajaBoveda = () => {
    const { recibos, anularRecibo } = useCaja();
    const [activeTab, setActiveTab] = useState('operaciones');
    const [searchTerm, setSearchTerm] = useState('');
    const [filter, setFilter] = useState('Todos');

    const formatMoney = (amount) => new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount || 0);

    const filtrados = recibos.filter(r => {
        const matchesSearch = r.numero.toLowerCase().includes(searchTerm.toLowerCase()) || r.cliente.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesFilter = filter === 'Todos' || r.estado === filter;
        return matchesSearch && matchesFilter;
    });

    const renderEmptyTab = (title, desc) => (
        <div className="animate-fade-in" style={{ padding: '3rem', textAlign: 'center' }}>
            <div style={{ width: 64, height: 64, margin: '0 auto 1.5rem', background: 'var(--primary-light)', color: 'var(--primary)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {TABS.find(t => t.id === activeTab)?.icon({ size: 32 })}
            </div>
            <h2 style={{ fontSize: '1.25rem', marginBottom: '0.5rem' }}>{title}</h2>
            <p style={{ color: 'var(--text-muted)' }}>{desc}</p>
        </div>
    );

    return (
        <div className="animate-up" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Caja y Bóveda</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Administración integral de tesorería, operaciones de caja e incidencias</p>
                </div>
            </div>

            {/* Ribbon-like Tabs */}
            <div className="card" style={{ padding: '0.5rem', marginBottom: '1.5rem', display: 'flex', gap: '0.5rem', overflowX: 'auto', whiteSpace: 'nowrap' }}>
                {TABS.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            style={{
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.75rem 1rem',
                                border: 'none',
                                background: isActive ? 'var(--primary-light)' : 'transparent',
                                color: isActive ? 'var(--primary)' : 'var(--text-muted)',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                minWidth: '100px'
                            }}
                        >
                            <Icon size={22} strokeWidth={isActive ? 2.5 : 1.5} />
                            <span style={{ fontSize: '0.75rem', fontWeight: isActive ? 700 : 500 }}>
                                {tab.label}
                            </span>
                        </button>
                    );
                })}
            </div>

            {/* Tab Contents */}
            <div className="card" style={{ flex: 1, overflowY: 'auto', padding: activeTab === 'operaciones' ? '1.5rem 0 0 0' : '1.5rem' }}>
                {activeTab === 'operaciones' && (
                    <div className="animate-fade-in">
                        <div style={{ padding: '0 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.5rem', width: '100%' }}>
                                <div style={{ padding: '1.25rem', borderLeft: '4px solid var(--success)', background: '#f8fafc', borderRadius: '8px' }}>
                                    <div style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Ingresos Hoy</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 800 }}>{formatMoney(recibos.reduce((acc, r) => r.estado === 'Valido' ? acc + r.monto : acc, 0))}</div>
                                </div>
                                <div style={{ padding: '1.25rem', borderLeft: '4px solid var(--primary)', background: '#f8fafc', borderRadius: '8px' }}>
                                    <div style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Recibos Emitidos</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 800 }}>{recibos.length}</div>
                                </div>
                                <div style={{ padding: '1.25rem', borderLeft: '4px solid var(--warning)', background: '#f8fafc', borderRadius: '8px' }}>
                                    <div style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Caja Activa</div>
                                    <div style={{ fontSize: '1rem', fontWeight: 700, color: 'var(--success)', display: 'flex', alignItems: 'center', gap: '0.5rem', marginTop: '0.2rem' }}><CheckCircle size={16} /> CAJA-01</div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end' }}>
                                    <div style={{ position: 'relative', width: '100%' }}>
                                        <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                                        <input type="text" placeholder="Buscar recibo..." className="input-field" style={{ paddingLeft: '2.5rem', marginBottom: 0 }} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div style={{ borderTop: '1px solid var(--border)' }}>
                            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                                <thead>
                                    <tr style={{ textAlign: 'left', background: 'var(--background)', fontSize: '0.75rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>
                                        <th style={{ padding: '1rem 1.5rem' }}>Número</th>
                                        <th style={{ padding: '1rem' }}>Fecha</th>
                                        <th style={{ padding: '1rem' }}>Socio / Cliente</th>
                                        <th style={{ padding: '1rem' }}>Concepto</th>
                                        <th style={{ padding: '1rem', textAlign: 'right' }}>Monto</th>
                                        <th style={{ padding: '1rem', textAlign: 'center' }}>Estado</th>
                                        <th style={{ padding: '1rem 1.5rem', textAlign: 'right' }}>Acciones</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filtrados.length === 0 ? (
                                        <tr><td colSpan={7} style={{ padding: '3rem', textAlign: 'center', color: 'var(--text-muted)' }}>No se encontraron recibos de operaciones.</td></tr>
                                    ) : (
                                        filtrados.slice().reverse().map(r => (
                                            <tr key={r.id} style={{ borderBottom: '1px solid var(--border)', opacity: r.estado === 'Anulado' ? 0.6 : 1 }}>
                                                <td style={{ padding: '1rem 1.5rem', fontWeight: 700 }}>{r.numero}</td>
                                                <td style={{ padding: '1rem', fontSize: '0.85rem' }}>{new Date(r.fecha).toLocaleDateString()}</td>
                                                <td style={{ padding: '1rem', fontSize: '0.85rem', fontWeight: 500 }}>{r.cliente}</td>
                                                <td style={{ padding: '1rem', fontSize: '0.85rem' }}>{r.concepto}</td>
                                                <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 800 }}>{formatMoney(r.monto)}</td>
                                                <td style={{ padding: '1rem', textAlign: 'center' }}>
                                                    <span style={{ padding: '0.25rem 0.6rem', borderRadius: '1rem', fontSize: '0.7rem', fontWeight: 800, background: r.estado === 'Valido' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)', color: r.estado === 'Valido' ? 'var(--success)' : 'var(--danger)' }}>{r.estado}</span>
                                                </td>
                                                <td style={{ padding: '1rem 1.5rem', textAlign: 'right' }}>
                                                    <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                                                        <button className="btn btn-secondary" style={{ padding: '0.4rem' }}><Printer size={16} /></button>
                                                        {r.estado === 'Valido' && (
                                                            <button className="btn btn-secondary" style={{ padding: '0.4rem', color: 'var(--danger)' }} onClick={() => { const m = prompt('Motivo:'); if (m) anularRecibo(r.id, m); }}>
                                                                <XCircle size={16} />
                                                            </button>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {activeTab === 'pagos' && renderEmptyTab('Gestión de Pagos por Caja', 'Módulo para registrar salidas de efectivo, pagos de cheques y desembolsos directos.')}
                {activeTab === 'documentos' && renderEmptyTab('Gestión Documental', 'Archivo de cuadres, comprobantes firmados y documentos de respaldo de la jornada.')}
                {activeTab === 'bovedas' && (
                    <div className="animate-fade-in" style={{ textAlign: 'center', padding: '3rem' }}>
                        <Landmark size={48} style={{ color: 'var(--primary)', opacity: 0.5, marginBottom: '1rem' }} />
                        <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Gestión de Bóveda Central</h2>
                        <p style={{ color: 'var(--text-muted)', marginBottom: '1.5rem' }}>Acceso directo al control de custodia de valores y reservas.</p>
                        <button className="btn btn-primary" onClick={() => window.location.href = '/boveda'}>Ir a Bóveda Central ⇾</button>
                    </div>
                )}
                {activeTab === 'transacciones' && renderEmptyTab('Diario de Transacciones', 'Bitácora completa y auditable de todos los eventos ocurridos en caja.')}
                {activeTab === 'incidencias' && renderEmptyTab('Registro de Incidencias', 'Reporte de sobrantes, faltantes y errores de cuadre con seguimiento.')}
                {activeTab === 'informes' && renderEmptyTab('Informes de Tesorería', 'Generación de reportes de final del día, arqueos y resúmenes de movimiento.')}
            </div>
        </div>
    );
};

export default CajaBoveda;

import React, { useState } from 'react';
import { useCentrosCosto } from '../context/CentrosCostoContext';
import { useContabilidad } from '../context/ContabilidadContext';
import { useCuentas } from '../context/CuentasContext';
import { Plus, Trash2, BarChart2, Target } from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const PALETTE = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316', '#ec4899'];

const CentrosCosto = () => {
    const { centros, crearCentro, toggleCentro, eliminarCentro } = useCentrosCosto();
    const { asientos } = useContabilidad();
    const { cuentas } = useCuentas();

    const [showModal, setShowModal] = useState(false);
    const [confirmDelete, setConfirmDelete] = useState({ open: false, id: null });
    const [form, setForm] = useState({ codigo: '', nombre: '', color: PALETTE[0] });
    const [centroSeleccionado, setCentroSeleccionado] = useState(null);

    const formatMoney = (amount) =>
        new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount || 0);

    // Calcular gasto/ingreso por centro
    const calcularPorCentro = (centroId) => {
        let ingresos = 0, gastos = 0;
        asientos.forEach(a => {
            if (a.centroCostoId !== centroId) return;
            (a.detalles || []).forEach(m => {
                const cuentaId = m.cuentaId;
                if (cuentaId?.startsWith('4')) ingresos += (Number(m.credito) || 0);
                if (cuentaId?.startsWith('5') || cuentaId?.startsWith('6')) gastos += (Number(m.debito) || 0);
            });
        });
        return { ingresos, gastos, neto: ingresos - gastos };
    };

    const handleCrear = (e) => {
        e.preventDefault();
        crearCentro(form);
        setShowModal(false);
        setForm({ codigo: '', nombre: '', color: PALETTE[0] });
    };

    return (
        <div className="animate-up">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Centros de Costo</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Analiza la rentabilidad por departamento, área o proyecto.</p>
                </div>
                <button className="btn btn-primary" onClick={() => setShowModal(true)}>
                    <Plus size={18} /> Nuevo Centro
                </button>
            </div>

            {/* Cards de Centros */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
                {centros.map(centro => {
                    const stats = calcularPorCentro(centro.id);
                    return (
                        <div key={centro.id} className="card" style={{ padding: '1.75rem', borderTop: `4px solid ${centro.color}`, opacity: centro.activo ? 1 : 0.55, cursor: 'pointer', transition: 'all 0.2s' }}
                            onClick={() => setCentroSeleccionado(centro.id === centroSeleccionado ? null : centro.id)}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.25rem' }}>
                                <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
                                    <div style={{ width: 40, height: 40, borderRadius: 10, background: centro.color, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 800, fontSize: '0.875rem' }}>
                                        {centro.codigo.slice(0, 2)}
                                    </div>
                                    <div>
                                        <div style={{ fontWeight: 700, fontSize: '1.05rem' }}>{centro.nombre}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{centro.codigo}</div>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', gap: '0.35rem' }}>
                                    <button style={{ background: 'none', border: 'none', cursor: 'pointer', color: centro.activo ? 'var(--success)' : 'var(--text-muted)', padding: '4px' }}
                                        onClick={(e) => { e.stopPropagation(); toggleCentro(centro.id); }} title={centro.activo ? 'Pausar' : 'Activar'}>
                                        <Target size={16} />
                                    </button>
                                    <button style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--danger)', padding: '4px' }}
                                        onClick={(e) => { e.stopPropagation(); setConfirmDelete({ open: true, id: centro.id }); }}>
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                                <div style={{ padding: '0.6rem', background: 'rgba(16,185,129,0.08)', borderRadius: '8px' }}>
                                    <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 700, marginBottom: '0.15rem' }}>INGRESOS</div>
                                    <div style={{ fontWeight: 700, color: 'var(--success)', fontSize: '0.9rem' }}>{formatMoney(stats.ingresos)}</div>
                                </div>
                                <div style={{ padding: '0.6rem', background: 'rgba(239,68,68,0.08)', borderRadius: '8px' }}>
                                    <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 700, marginBottom: '0.15rem' }}>GASTOS</div>
                                    <div style={{ fontWeight: 700, color: 'var(--danger)', fontSize: '0.9rem' }}>{formatMoney(stats.gastos)}</div>
                                </div>
                            </div>

                            <div style={{ marginTop: '0.75rem', padding: '0.6rem 1rem', background: 'var(--background)', borderRadius: '8px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-muted)' }}>RESULTADO</span>
                                <span style={{ fontWeight: 800, color: stats.neto >= 0 ? 'var(--success)' : 'var(--danger)' }}>{formatMoney(stats.neto)}</span>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Nota informativa */}
            <div style={{ padding: '1.25rem 1.5rem', background: 'var(--primary-light)', borderRadius: 'var(--radius-md)', border: '1px solid rgba(37,99,235,0.15)', fontSize: '0.875rem', color: 'var(--primary)' }}>
                <strong>💡 ¿Cómo asignar asientos a un centro de costo?</strong> Al registrar entradas de diario manualmente, selecciona el Centro de Costo correspondiente. En futuras actualizaciones, facturas y compras también podrán asignarse a un centro.
            </div>

            {/* Modal Nuevo Centro */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="card" style={{ width: '100%', maxWidth: '450px', padding: 0 }}>
                        <div style={{ padding: '1.5rem', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between' }}>
                            <h2 style={{ fontSize: '1.125rem', fontWeight: 700 }}>Nuevo Centro de Costo</h2>
                            <button onClick={() => setShowModal(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '1.5rem', color: 'var(--text-muted)' }}>×</button>
                        </div>
                        <form onSubmit={handleCrear} style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">Código</label>
                                    <input className="input-field" style={{ textTransform: 'uppercase' }} value={form.codigo} onChange={e => setForm(p => ({ ...p, codigo: e.target.value.toUpperCase() }))} placeholder="MKTG" required maxLength={6} />
                                </div>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">Nombre</label>
                                    <input className="input-field" value={form.nombre} onChange={e => setForm(p => ({ ...p, nombre: e.target.value }))} placeholder="Marketing" required />
                                </div>
                            </div>
                            <div className="input-group" style={{ marginBottom: 0 }}>
                                <label className="input-label">Color Identificador</label>
                                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginTop: '0.25rem' }}>
                                    {PALETTE.map(color => (
                                        <div key={color} onClick={() => setForm(p => ({ ...p, color }))} style={{
                                            width: 32, height: 32, borderRadius: '50%', background: color, cursor: 'pointer',
                                            border: form.color === color ? '3px solid var(--primary)' : '3px solid transparent',
                                            outline: form.color === color ? '2px solid white' : 'none',
                                            transition: 'all 0.15s', transform: form.color === color ? 'scale(1.2)' : 'scale(1)'
                                        }} />
                                    ))}
                                </div>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '0.5rem' }}>
                                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Cancelar</button>
                                <button type="submit" className="btn btn-primary">Crear Centro</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <ConfirmModal
                isOpen={confirmDelete.open}
                onClose={() => setConfirmDelete({ open: false, id: null })}
                onConfirm={() => { eliminarCentro(confirmDelete.id); setConfirmDelete({ open: false, id: null }); }}
                title="Eliminar Centro de Costo"
                message="¿Estás seguro de eliminar este centro? Los asientos ya asignados conservarán su referencia."
            />
        </div>
    );
};

export default CentrosCosto;

import React, { useState } from 'react';
import { useCierre } from '../context/CierreContext';
import { useContabilidad } from '../context/ContabilidadContext';
import { Lock, AlertTriangle, CheckCircle, TrendingUp, TrendingDown, DollarSign, BookOpen, Archive } from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const CierreFiscal = () => {
    const { cierres, ejecutarCierreFiscal, saldosApertura, guardarSaldoApertura, aplicarSaldosApertura } = useCierre();
    const { asientos } = useContabilidad();

    const [año, setAño] = useState(new Date().getFullYear());
    const [confirmCierre, setConfirmCierre] = useState(false);
    const [resultado, setResultado] = useState(null);
    const [tab, setTab] = useState('cierre');

    const formatMoney = (amount) =>
        new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount || 0);

    const handleEjecutar = () => {
        try {
            const res = ejecutarCierreFiscal(año);
            setResultado(res);
            setConfirmCierre(false);
        } catch (e) {
            alert('Error al ejecutar el cierre: ' + e.message);
            setConfirmCierre(false);
        }
    };

    return (
        <div className="animate-up">
            <div style={{ marginBottom: '2rem' }}>
                <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Cierre Fiscal y Apertura</h1>
                <p style={{ color: 'var(--text-muted)' }}>Ejecuta el cierre contable anual y registra los saldos iniciales de migración.</p>
            </div>

            {/* Tabs */}
            <div style={{ display: 'flex', gap: '0', marginBottom: '2rem', background: 'var(--background)', borderRadius: 'var(--radius-md)', padding: '4px', width: 'fit-content', border: '1px solid var(--border)' }}>
                {[{ id: 'cierre', label: '🔒 Cierre de Ejercicio' }, { id: 'apertura', label: '📂 Saldos de Apertura' }, { id: 'historial', label: '📋 Historial' }].map(t => (
                    <button key={t.id} onClick={() => setTab(t.id)}
                        style={{
                            padding: '0.625rem 1.25rem', borderRadius: 'var(--radius-sm)', border: 'none', cursor: 'pointer', fontSize: '0.875rem', fontWeight: 600, transition: 'all 0.2s',
                            background: tab === t.id ? 'var(--primary)' : 'transparent',
                            color: tab === t.id ? 'white' : 'var(--text-muted)'
                        }}>{t.label}</button>
                ))}
            </div>

            {/* === TAB: CIERRE === */}
            {tab === 'cierre' && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
                    <div>
                        <div className="card" style={{ padding: '2rem', borderLeft: '4px solid var(--warning)' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
                                <AlertTriangle size={24} color="var(--warning)" />
                                <h2 style={{ fontSize: '1.125rem', fontWeight: 700 }}>Ejecutar Cierre de Ejercicio</h2>
                            </div>
                            <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem', marginBottom: '1.5rem', lineHeight: 1.7 }}>
                                Este proceso <strong>salda todas las cuentas de Ingresos y Gastos</strong> (cuentas 4x, 5x, 6x), transfiere la
                                utilidad/pérdida neta a la cuenta de Resultados del Ejercicio (patrimonio), y deja los libros listos para el nuevo año fiscal.
                            </p>

                            <div className="input-group">
                                <label className="input-label">Año Fiscal a Cerrar</label>
                                <input type="number" className="input-field" value={año} onChange={e => setAño(e.target.value)} min="2000" max="2099" />
                            </div>

                            <div style={{ padding: '1rem', background: 'rgba(239,68,68,0.08)', borderRadius: 'var(--radius-md)', marginBottom: '1.5rem', fontSize: '0.8125rem', color: 'var(--danger)' }}>
                                ⚠️ <strong>Esta acción no se puede deshacer.</strong> Asegúrate de tener un respaldo y de que todos los asientos del año estén registrados antes de continuar.
                            </div>

                            <button className="btn btn-primary" style={{ width: '100%', background: 'linear-gradient(135deg, #dc2626, #b91c1c)' }}
                                onClick={() => setConfirmCierre(true)}>
                                <Lock size={18} /> Ejecutar Cierre Fiscal {año}
                            </button>
                        </div>

                        {resultado && (
                            <div className="card" style={{ padding: '2rem', marginTop: '1.5rem', borderLeft: '4px solid var(--success)', background: 'rgba(16,185,129,0.05)' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
                                    <CheckCircle size={24} color="var(--success)" />
                                    <h2 style={{ fontSize: '1.125rem', fontWeight: 700, color: 'var(--success)' }}>¡Cierre Ejecutado con Éxito!</h2>
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Total Ingresos</span>
                                        <span style={{ fontWeight: 700, color: 'var(--success)' }}>{formatMoney(resultado.ingresos)}</span>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Total Gastos</span>
                                        <span style={{ fontWeight: 700, color: 'var(--danger)' }}>{formatMoney(resultado.gastos)}</span>
                                    </div>
                                    <div style={{ borderTop: '2px solid var(--border)', paddingTop: '0.75rem', display: 'flex', justifyContent: 'space-between' }}>
                                        <span style={{ fontWeight: 700 }}>Utilidad / Pérdida Neta</span>
                                        <span style={{ fontSize: '1.25rem', fontWeight: 800, color: resultado.utilidad >= 0 ? 'var(--success)' : 'var(--danger)' }}>
                                            {resultado.utilidad >= 0 ? <TrendingUp size={16} style={{ display: 'inline', marginRight: 4 }} /> : <TrendingDown size={16} style={{ display: 'inline', marginRight: 4 }} />}
                                            {formatMoney(resultado.utilidad)}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="card" style={{ padding: '2rem' }}>
                        <h2 style={{ fontSize: '1.125rem', fontWeight: 700, marginBottom: '1rem' }}>¿Cómo funciona el cierre?</h2>
                        {[
                            { step: '1', title: 'Calcular Resultado', desc: 'El sistema suma todos los ingresos (4xxx) y resta todos los gastos (5xxx, 6xxx) del año.' },
                            { step: '2', title: 'Generar Asiento de Cierre', desc: 'Se crea un asiento que lleva a cero todas las cuentas de resultado (Débito en Ingresos, Crédito en Gastos).' },
                            { step: '3', title: 'Transferir al Patrimonio', desc: 'La utilidad neta se acredita a "Resultados del Ejercicio" (cuenta 3102). Una pérdida se debita.' },
                            { step: '4', title: 'Nuevo Ejercicio Limpio', desc: 'Las cuentas nominales quedan en cero, listas para el año siguiente.' }
                        ].map(s => (
                            <div key={s.step} style={{ display: 'flex', gap: '1rem', marginBottom: '1.25rem' }}>
                                <div style={{ width: 32, height: 32, borderRadius: '50%', background: 'var(--primary)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800, flexShrink: 0, fontSize: '0.875rem' }}>{s.step}</div>
                                <div>
                                    <div style={{ fontWeight: 700, marginBottom: '0.2rem' }}>{s.title}</div>
                                    <div style={{ color: 'var(--text-muted)', fontSize: '0.8125rem', lineHeight: 1.6 }}>{s.desc}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* === TAB: APERTURA === */}
            {tab === 'apertura' && (
                <div className="card" style={{ padding: '2rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <div>
                            <h2 style={{ fontSize: '1.125rem', fontWeight: 700 }}>Saldos Iniciales de Apertura</h2>
                            <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem', marginTop: '0.25rem' }}>
                                Ingresa los saldos de tu empresa antes de empezar a usar Iubel ERP. Solo debes hacerlo una vez.
                            </p>
                        </div>
                        <button className="btn btn-primary" onClick={aplicarSaldosApertura}>
                            <BookOpen size={18} /> Aplicar como Asiento Inicial
                        </button>
                    </div>

                    <div style={{ display: 'grid', gap: '0.75rem' }}>
                        {[
                            { id: '110101', nombre: 'Caja', tipo: 'deudor' },
                            { id: '110102', nombre: 'Banco (Cuenta Corriente)', tipo: 'deudor' },
                            { id: '110301', nombre: 'Cuentas por Cobrar', tipo: 'deudor' },
                            { id: '110401', nombre: 'Inventario', tipo: 'deudor' },
                            { id: '120101', nombre: 'Activos Fijos', tipo: 'deudor' },
                            { id: '210101', nombre: 'Cuentas por Pagar', tipo: 'acreedor' },
                            { id: '210201', nombre: 'Préstamos por Pagar', tipo: 'acreedor' },
                            { id: '310101', nombre: 'Capital Social', tipo: 'acreedor' },
                            { id: '310201', nombre: 'Resultados Acumulados', tipo: 'acreedor' },
                        ].map(cuenta => {
                            const saldo = saldosApertura.find(s => s.cuentaId === cuenta.id);
                            return (
                                <div key={cuenta.id} style={{ display: 'grid', gridTemplateColumns: '1fr 200px', gap: '1rem', alignItems: 'center', padding: '0.75rem 1rem', background: 'var(--background)', borderRadius: 'var(--radius-md)' }}>
                                    <div>
                                        <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{cuenta.nombre}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{cuenta.id} • {cuenta.tipo === 'deudor' ? '⬆ Activo / Deudor' : '⬇ Pasivo / Acreedor'}</div>
                                    </div>
                                    <input
                                        type="number"
                                        className="input-field"
                                        style={{ marginBottom: 0, textAlign: 'right' }}
                                        placeholder="0.00"
                                        value={saldo?.monto || ''}
                                        onChange={e => guardarSaldoApertura(cuenta.id, e.target.value, cuenta.tipo)}
                                    />
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* === TAB: HISTORIAL === */}
            {tab === 'historial' && (
                <div className="card">
                    {cierres.length === 0 ? (
                        <div style={{ padding: '4rem', textAlign: 'center', color: 'var(--text-muted)' }}>
                            <Archive size={48} style={{ marginBottom: '1rem', opacity: 0.4 }} />
                            <div>No se han ejecutado cierres fiscales aún.</div>
                        </div>
                    ) : (
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead>
                                <tr style={{ background: 'var(--background)', fontSize: '0.8rem' }}>
                                    <th style={{ padding: '1rem', textAlign: 'left' }}>Año</th>
                                    <th style={{ padding: '1rem', textAlign: 'left' }}>Fecha de Cierre</th>
                                    <th style={{ padding: '1rem', textAlign: 'right' }}>Ingresos</th>
                                    <th style={{ padding: '1rem', textAlign: 'right' }}>Gastos</th>
                                    <th style={{ padding: '1rem', textAlign: 'right' }}>Utilidad/Pérdida</th>
                                </tr>
                            </thead>
                            <tbody>
                                {[...cierres].reverse().map(c => (
                                    <tr key={c.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                        <td style={{ padding: '1rem', fontWeight: 700 }}>{c.año}</td>
                                        <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{new Date(c.fechaCierre).toLocaleDateString('es-DO')}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right', color: 'var(--success)', fontWeight: 600 }}>{formatMoney(c.ingresos)}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right', color: 'var(--danger)', fontWeight: 600 }}>{formatMoney(c.gastos)}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 800, color: c.utilidad >= 0 ? 'var(--success)' : 'var(--danger)' }}>
                                            {formatMoney(c.utilidad)}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            )}

            <ConfirmModal
                isOpen={confirmCierre}
                onClose={() => setConfirmCierre(false)}
                onConfirm={handleEjecutar}
                title={`⚠️ Confirmar Cierre Fiscal ${año}`}
                message={`¿Estás seguro de que deseas ejecutar el cierre del ejercicio fiscal ${año}? Esta acción es irreversible y generará el asiento de cierre automáticamente.`}
            />
        </div>
    );
};

