import React, { useState } from 'react';
import { useInventario } from '../context/InventarioContext';
import { useFacturacion } from '../context/FacturacionContext';
import { useMoneda } from '../context/MonedaContext';
import {
    ShoppingCart, Plus, Trash2, CheckCircle, Globe,
    FileText, Users, ClipboardList, Package, CreditCard, BarChart
} from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const TABS = [
    { id: 'facturacion', label: 'Facturación', icon: FileText },
    { id: 'vendedores', label: 'Vendedores', icon: Users },
    { id: 'cotizaciones', label: 'Cotizaciones', icon: ClipboardList },
    { id: 'pedidos', label: 'Pedidos', icon: Package },
    { id: 'clientes', label: 'Clientes', icon: Users },
    { id: 'pagos', label: 'Pagos', icon: CreditCard },
    { id: 'informes', label: 'Informes', icon: BarChart },
];

const Facturacion = () => {
    const { articulos } = useInventario();
    const { guardarFactura, facturas, eliminarFactura } = useFacturacion();
    const { monedas } = useMoneda();

    const [activeTab, setActiveTab] = useState('facturacion');

    // ── Delete Confirmation ──────────────────────────────────────────
    const [confirmDelete, setConfirmDelete] = useState({ open: false, id: null });

    const handleDeleteFactura = (id) => setConfirmDelete({ open: true, id });
    const confirmDeleteAction = () => {
        if (confirmDelete.id) {
            eliminarFactura(confirmDelete.id);
            setConfirmDelete({ open: false, id: null });
        }
    };

    // ── Form Fields ──────────────────────────────────────────────────
    const [clienteNombre, setClienteNombre] = useState('');
    const [clienteRnc, setClienteRnc] = useState('');
    const [tipoComprobante, setTipoComprobante] = useState('B02');
    const [condicion, setCondicion] = useState('Contado');
    const [monedaId, setMonedaId] = useState('1');

    // ── Cart State ────────────────────────────────────────────────────
    const [carrito, setCarrito] = useState([]);
    const [articuloId, setArticuloId] = useState('');
    const [cantidadInput, setCantidadInput] = useState('1');
    const [facturaGuardada, setFacturaGuardada] = useState(null);
    const [errorMsg, setErrorMsg] = useState('');

    const activosParaVenta = articulos.filter(a => a.activa);

    // ── AGREGAR AL CARRITO ─────────────────────────────────────────────
    const handleAgregarAlCarrito = () => {
        setErrorMsg('');
        if (!articuloId) return setErrorMsg('Seleccione un artículo de la lista.');

        const cantidad = parseInt(cantidadInput, 10);
        if (isNaN(cantidad) || cantidad <= 0) return setErrorMsg('La cantidad debe ser un número mayor a 0.');

        const articulo = articulos.find(a => String(a.id) === String(articuloId));
        if (!articulo) return setErrorMsg('Artículo no encontrado.');

        if (articulo.tipo === 'Producto') {
            const existencia = Number(articulo.existencia) || 0;
            const yaEnCarrito = carrito.find(i => String(i.articulo.id) === String(articuloId));
            const totalTrasAgregar = (yaEnCarrito ? Number(yaEnCarrito.cantidad) : 0) + cantidad;
            if (totalTrasAgregar > existencia) {
                return setErrorMsg(`Existencia insuficiente (${existencia} disponibles).`);
            }
        }

        setCarrito(prev => {
            const idx = prev.findIndex(i => String(i.articulo.id) === String(articuloId));
            if (idx >= 0) {
                const updated = [...prev];
                updated[idx] = { ...updated[idx], cantidad: Number(updated[idx].cantidad) + cantidad };
                return updated;
            }
            return [...prev, { articulo: { ...articulo }, cantidad, precio: Number(articulo.precioVenta) || 0 }];
        });

        setArticuloId('');
        setCantidadInput('1');
    };

    const handleRemoverDelCarrito = (artId) => setCarrito(prev => prev.filter(i => String(i.articulo.id) !== String(artId)));

    // ── TOTALS ─────────────────────────────────────────────────────────
    const subtotal = carrito.reduce((acc, item) => acc + (Number(item.cantidad) * Number(item.precio)), 0);
    const totalItbis = carrito.reduce((acc, item) => item.articulo.gravado ? acc + (Number(item.cantidad) * Number(item.precio) * 0.18) : acc, 0);
    const totalGeneral = subtotal + totalItbis;

    const selectedMoneda = monedas.find(m => String(m.id) === String(monedaId)) || monedas[0] || { codigo: 'DOP', simbolo: 'RD$', tasa: 1 };
    const formatMoney = (amount, m = selectedMoneda) => {
        try {
            return new Intl.NumberFormat('es-DO', { style: 'currency', currency: m.codigo, currencyDisplay: 'symbol' }).format(amount);
        } catch {
            return `${m.simbolo || 'RD$'}${Number(amount).toFixed(2)}`;
        }
    };

    // ── GUARDAR FACTURA ────────────────────────────────────────────────
    const handleGuardarFactura = () => {
        if (carrito.length === 0) return alert('Debe agregar al menos un artículo.');
        const data = { clienteNombre: clienteNombre.trim() || 'Cliente Genérico', clienteRnc, tipoComprobante, condicion, subtotal, itbis: totalItbis, total: totalGeneral, monedaId, tasa: selectedMoneda.tasa || 1 };
        setFacturaGuardada(guardarFactura(data, carrito));
        setCarrito([]); setClienteNombre(''); setClienteRnc(''); setArticuloId(''); setCantidadInput('1');
    };

    const renderEmptyCatalog = (title, desc) => (
        <div className="animate-fade-in" style={{ padding: '3rem', textAlign: 'center' }}>
            <div style={{ width: 64, height: 64, margin: '0 auto 1.5rem', background: 'var(--primary-light)', color: 'var(--primary)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {TABS.find(t => t.id === activeTab)?.icon({ size: 32 })}
            </div>
            <h2 style={{ fontSize: '1.25rem', marginBottom: '0.5rem' }}>{title}</h2>
            <p style={{ color: 'var(--text-muted)', marginBottom: '1.5rem' }}>{desc}</p>
            <button className="btn btn-primary" onClick={() => window.location.href = `/${activeTab}`}>Ir a {title} ⇾</button>
        </div>
    );

    return (
        <div className="animate-up" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Facturación y Ventas</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Módulo Comercial para la gestión integral de ventas, cobros y clientes</p>
                </div>
            </div>

            {/* Ribbon-like Tabs */}
            <div className="card scrollable-tabs" style={{ padding: '0.5rem', marginBottom: '1.5rem', display: 'flex', gap: '0.5rem', overflowX: 'auto', whiteSpace: 'nowrap' }}>
                {TABS.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => { setActiveTab(tab.id); setFacturaGuardada(null); }}
                            style={{
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.75rem 1.25rem',
                                border: 'none',
                                background: isActive ? 'var(--primary-light)' : 'transparent',
                                color: isActive ? 'var(--primary)' : 'var(--text-muted)',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                minWidth: '110px'
                            }}
                        >
                            <Icon size={24} strokeWidth={isActive ? 2.5 : 1.5} />
                            <span style={{ fontSize: '0.75rem', fontWeight: isActive ? 700 : 500 }}>{tab.label}</span>
                        </button>
                    );
                })}
            </div>

            {/* Tab Contents */}
            <div className="card" style={{ flex: 1, overflowY: 'auto', padding: activeTab === 'facturacion' ? '1.5rem' : 0 }}>
                {activeTab === 'facturacion' && (
                    <div className="animate-fade-in">
                        {facturaGuardada ? (
                            <div style={{ padding: '3rem', textAlign: 'center' }}>
                                <CheckCircle size={64} color="var(--success)" style={{ margin: '0 auto 1rem auto' }} />
                                <h2 style={{ fontSize: '1.5rem', fontWeight: 700, marginBottom: '0.5rem' }}>¡Factura Creada Exitosamente!</h2>
                                <p style={{ color: 'var(--text-muted)', marginBottom: '1.5rem' }}>Asiento contable y descargo de inventario generados automáticamente.</p>
                                <div style={{ background: 'var(--background)', padding: '1.5rem', borderRadius: '12px', display: 'inline-block', textAlign: 'left', marginBottom: '2rem' }}>
                                    <p><strong>N° Interno:</strong> {facturaGuardada.numeroInterno}</p>
                                    <p><strong>NCF:</strong> {facturaGuardada.ncf}</p>
                                    <p><strong>Total:</strong> {formatMoney(facturaGuardada.total)}</p>
                                </div>
                                <div><button className="btn btn-primary" onClick={() => setFacturaGuardada(null)}>Nueva Factura</button></div>
                            </div>
                        ) : (
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 340px', gap: '1.5rem' }}>
                                {/* Formulario Izquierdo */}
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                                    {/* Datos Cliente */}
                                    <div style={{ background: '#f8fafc', padding: '1.5rem', borderRadius: '12px', border: '1px solid var(--border)' }}>
                                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1rem' }}>Datos del Cliente</h3>
                                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                            <div className="input-group" style={{ marginBottom: 0 }}>
                                                <label className="input-label">Cliente</label>
                                                <input type="text" className="input-field" value={clienteNombre} onChange={e => setClienteNombre(e.target.value)} placeholder="Ej: Juan Pérez" />
                                            </div>
                                            <div className="input-group" style={{ marginBottom: 0 }}>
                                                <label className="input-label">RNC o Cédula</label>
                                                <input type="text" className="input-field" value={clienteRnc} onChange={e => setClienteRnc(e.target.value)} />
                                            </div>
                                            <div className="input-group" style={{ marginBottom: 0 }}>
                                                <label className="input-label">Tipo NCF (Comprobante)</label>
                                                <select className="input-field" value={tipoComprobante} onChange={e => setTipoComprobante(e.target.value)}>
                                                    <option value="B02">Consumo Final (B02)</option>
                                                    <option value="B01">Crédito Fiscal (B01)</option>
                                                    <option value="B15">Gubernamental (B15)</option>
                                                </select>
                                            </div>
                                            <div className="input-group" style={{ marginBottom: 0 }}>
                                                <label className="input-label">Moneda</label>
                                                <select className="input-field" value={monedaId} onChange={e => setMonedaId(e.target.value)}>
                                                    {monedas.map(m => <option key={m.id} value={m.id}>{m.codigo} - {m.simbolo}</option>)}
                                                </select>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Agregar Artículos */}
                                    <div style={{ background: 'var(--background)', padding: '1.5rem', borderRadius: '12px', border: '1px solid var(--border)' }}>
                                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1rem' }}>Agregar Conceptos</h3>
                                        {errorMsg && <div style={{ background: '#fee2e2', color: '#dc2626', padding: '0.75rem', borderRadius: '8px', marginBottom: '1rem', fontSize: '0.85rem' }}>{errorMsg}</div>}

                                        <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'flex-end', marginBottom: '1rem' }}>
                                            <div className="input-group" style={{ flex: 1, marginBottom: 0 }}>
                                                <label className="input-label">Artículo</label>
                                                <select className="input-field" value={articuloId} onChange={e => { setArticuloId(e.target.value); setErrorMsg(''); }}>
                                                    <option value="">-- Seleccione --</option>
                                                    {activosParaVenta.map(a => <option key={a.id} value={a.id}>{a.codigo} - {a.nombre} ({formatMoney(a.precioVenta)})</option>)}
                                                </select>
                                            </div>
                                            <div className="input-group" style={{ width: '80px', marginBottom: 0 }}>
                                                <label className="input-label">Cant</label>
                                                <input type="number" min="1" className="input-field" value={cantidadInput} onChange={e => setCantidadInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAgregarAlCarrito()} />
                                            </div>
                                            <button type="button" className="btn btn-secondary" style={{ height: '38px', background: 'var(--primary)', color: 'white', border: 'none' }} onClick={handleAgregarAlCarrito}><Plus size={18} /></button>
                                        </div>

                                        {/* Carrito Resumen Mini */}
                                        <div style={{ border: '1px solid var(--border)', borderRadius: '8px', overflow: 'hidden' }}>
                                            <table style={{ width: '100%', fontSize: '0.85rem' }}>
                                                <thead style={{ background: '#f1f5f9' }}>
                                                    <tr>
                                                        <th style={{ padding: '0.5rem', textAlign: 'center' }}>C</th>
                                                        <th style={{ padding: '0.5rem', textAlign: 'left' }}>Desc</th>
                                                        <th style={{ padding: '0.5rem', textAlign: 'right' }}>Total</th>
                                                        <th style={{ padding: '0.5rem', textAlign: 'center' }}></th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {carrito.map((item, idx) => (
                                                        <tr key={idx} style={{ borderTop: '1px solid var(--border)' }}>
                                                            <td style={{ padding: '0.5rem', textAlign: 'center', fontWeight: 700 }}>{item.cantidad}</td>
                                                            <td style={{ padding: '0.5rem' }}>{item.articulo.nombre}</td>
                                                            <td style={{ padding: '0.5rem', textAlign: 'right', fontWeight: 600 }}>{formatMoney(item.cantidad * item.precio)}</td>
                                                            <td style={{ padding: '0.5rem', textAlign: 'center' }}><button onClick={() => handleRemoverDelCarrito(item.articulo.id)} style={{ color: 'var(--danger)', background: 'none', border: 'none', cursor: 'pointer' }}><Trash2 size={14} /></button></td>
                                                        </tr>
                                                    ))}
                                                    {carrito.length === 0 && <tr><td colSpan={4} style={{ padding: '1rem', textAlign: 'center', color: 'var(--text-muted)' }}>No hay artículos en la factura</td></tr>}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>

                                {/* Sidebar Resumen Venta */}
                                <div>
                                    <div style={{ background: 'var(--primary-dark)', color: 'white', padding: '1.5rem', borderRadius: '12px', position: 'sticky', top: '2rem' }}>
                                        <h3 style={{ fontSize: '1.125rem', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}><ShoppingCart size={18} /> Resumen de Cobro</h3>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.75rem', fontSize: '0.9rem', opacity: 0.8 }}><span>Subtotal</span><span>{formatMoney(subtotal)}</span></div>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1.5rem', fontSize: '0.9rem', opacity: 0.8, borderBottom: '1px solid rgba(255,255,255,0.2)', paddingBottom: '1rem' }}><span>ITBIS (18%)</span><span>{formatMoney(totalItbis)}</span></div>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem', fontSize: '1.5rem', fontWeight: 800 }}><span>Total</span><span>{formatMoney(totalGeneral)}</span></div>
                                        <button className="btn" style={{ width: '100%', background: 'white', color: 'var(--primary-dark)', fontWeight: 700, padding: '0.85rem' }} onClick={handleGuardarFactura} disabled={carrito.length === 0}>Emitir Factura (F2)</button>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Historial rápido (solo si no se acaba de guardar) */}
                        {!facturaGuardada && facturas.length > 0 && (
                            <div style={{ marginTop: '2rem' }}>
                                <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1rem', color: 'var(--text-muted)' }}>Últimas Facturas Emitidas</h3>
                                <div style={{ display: 'flex', gap: '1rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
                                    {[...facturas].reverse().slice(0, 4).map(f => (
                                        <div key={f.id} style={{ minWidth: '220px', border: '1px solid var(--border)', borderRadius: '12px', padding: '1rem', background: 'var(--background)' }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                                <span style={{ fontWeight: 700, fontSize: '0.85rem' }}>{f.numeroInterno}</span>
                                                <span style={{ color: 'var(--success)', fontSize: '0.75rem', fontWeight: 700 }}>Valida</span>
                                            </div>
                                            <div style={{ fontSize: '0.85rem', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{f.clienteNombre}</div>
                                            <div style={{ fontWeight: 800, color: 'var(--primary)', marginTop: '0.5rem' }}>{formatMoney(f.total, monedas.find(m => String(m.id) === String(f.monedaId)))}</div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'vendedores' && renderEmptyCatalog('Fuerza de Ventas', 'Control de vendedores, cálculo de comisiones y zonas asignadas.')}
                {activeTab === 'cotizaciones' && renderEmptyCatalog('Cotizaciones', 'Gestión de cotizaciones, proformas y conversión a facturas firmes.')}
                {activeTab === 'pedidos' && renderEmptyCatalog('Pedidos y Despacho', 'Control de órdenes de entrega, logística y facturación parcial.')}
                {activeTab === 'clientes' && renderEmptyCatalog('Cartera de Clientes', 'Gestión de cuentas por cobrar (CXC), condiciones de crédito y cupos.')}
                {activeTab === 'pagos' && renderEmptyCatalog('Recibos de Ingreso (Pagos)', 'Aplicación de abonos a facturas de crédito y cruce de notas de crédito.')}
                {activeTab === 'informes' && renderEmptyCatalog('Análisis de Ventas', 'Métricas de facturación por producto, 606/607 fiscales y ranking de artículos.')}
            </div>

            <ConfirmModal isOpen={confirmDelete.open} onClose={() => setConfirmDelete({ open: false, id: null })} onConfirm={confirmDeleteAction} title="Anular Factura" message="¿Desea anular esta factura fiscal? (Se creará una entrada de diario de reversión)" />
        </div>
    );
};

export default Facturacion;

import React, { useState } from 'react';
import { useFixedAssets } from '../context/FixedAssetsContext';
import { useCuentas } from '../context/CuentasContext';
import { HardDrive, Plus, Calculator, History, Trash2, DollarSign } from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const FixedAssets = () => {
    const { activos, agregarActivo, procesarDepreciacionMensual, eliminarActivo } = useFixedAssets();
    const { cuentas } = useCuentas();
    const [confirmDelete, setConfirmDelete] = useState({ open: false, id: null, name: '' });

    const handleDeleteActivo = (id) => {
        const activo = activos.find(a => a.id === id);
        setConfirmDelete({ open: true, id, name: activo?.nombre });
    };

    const confirmDeleteAction = () => {
        if (confirmDelete.id) {
            eliminarActivo(confirmDelete.id);
            setConfirmDelete({ open: false, id: null });
        }
    };

    const [showModal, setShowModal] = useState(false);
    const [nuevoActivo, setNuevoActivo] = useState({
        nombre: '',
        tipo: 'Mobiliario',
        valor: 0,
        fechaCompra: new Date().toISOString().split('T')[0],
        vidaUtil: 5, // Años
        valorRescate: 0,
        cuentaActivoId: '1201', // Activos Fijos
        cuentaDepreciacionAcumuladaId: '120101',
        cuentaGastoDepreciacionId: '6101'
    });

    const formatMoney = (amount) => {
        return new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount);
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        agregarActivo({
            ...nuevoActivo,
            valor: Number(nuevoActivo.valor),
            vidaUtil: Number(nuevoActivo.vidaUtil),
            valorRescate: Number(nuevoActivo.valorRescate),
            depreciacionAcumulada: 0
        });
        setShowModal(false);
        setNuevoActivo({
            nombre: '',
            tipo: 'Mobiliario',
            valor: 0,
            fechaCompra: new Date().toISOString().split('T')[0],
            vidaUtil: 5,
            valorRescate: 0,
            cuentaActivoId: '1201',
            cuentaDepreciacionAcumuladaId: '120101',
            cuentaGastoDepreciacionId: '6101'
        });
    };

    return (
        <div className="animate-up">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Gestión de Activos Fijos</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Control de bienes, vida útil y depreciación automática.</p>
                </div>
                <div style={{ display: 'flex', gap: '1rem' }}>
                    <button className="btn btn-secondary" onClick={() => procesarDepreciacionMensual(new Date().toLocaleString('default', { month: 'long', year: 'numeric' }))}>
                        <Calculator size={18} /> Procesar Depreciación
                    </button>
                    <button className="btn btn-primary" onClick={() => setShowModal(true)}>
                        <Plus size={18} /> Nuevo Activo
                    </button>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
                <div className="card glass" style={{ textAlign: 'center', padding: '2rem' }}>
                    <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Valor Total en Libros</div>
                    <div style={{ fontSize: '2rem', fontWeight: 700, color: 'var(--primary)' }}>
                        {formatMoney(activos.reduce((acc, a) => acc + a.valor, 0))}
                    </div>
                </div>
                <div className="card glass" style={{ textAlign: 'center', padding: '2rem' }}>
                    <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Depreciación Acumulada</div>
                    <div style={{ fontSize: '2rem', fontWeight: 700, color: 'var(--danger)' }}>
                        {formatMoney(activos.reduce((acc, a) => acc + (a.depreciacionAcumulada || 0), 0))}
                    </div>
                </div>
                <div className="card glass" style={{ textAlign: 'center', padding: '2rem' }}>
                    <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Valor Residual Neto</div>
                    <div style={{ fontSize: '2rem', fontWeight: 700, color: 'var(--success)' }}>
                        {formatMoney(activos.reduce((acc, a) => acc + (a.residual || a.valor), 0))}
                    </div>
                </div>
            </div>

            <div className="card">
                <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead>
                            <tr style={{ borderBottom: '1px solid var(--border)' }}>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase' }}>Nombre / Tipo</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase' }}>Compra</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', textAlign: 'right' }}>Valor Orig.</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', textAlign: 'right' }}>Dep. Acum.</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', textAlign: 'right' }}>V. Residual</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', textAlign: 'center' }}>V. Útil</th>
                                <th style={{ padding: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', textAlign: 'center' }}>X</th>
                            </tr>
                        </thead>
                        <tbody>
                            {activos.map(activo => (
                                <tr key={activo.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem' }}>
                                        <div style={{ fontWeight: 600 }}>{activo.nombre}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{activo.tipo}</div>
                                    </td>
                                    <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{activo.fechaCompra}</td>
                                    <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 500 }}>{formatMoney(activo.valor)}</td>
                                    <td style={{ padding: '1rem', textAlign: 'right', color: 'var(--danger)' }}>{formatMoney(activo.depreciacionAcumulada || 0)}</td>
                                    <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 600, color: 'var(--success)' }}>{formatMoney(activo.residual || activo.valor)}</td>
                                    <td style={{ padding: '1rem', textAlign: 'center' }}>
                                        <span className="badge badge-info">{activo.vidaUtil} años</span>
                                    </td>
                                    <td style={{ padding: '1rem', textAlign: 'center' }}>
                                        <button
                                            className="btn"
                                            style={{ padding: '0.25rem', color: 'var(--danger)' }}
                                            onClick={() => handleDeleteActivo(activo.id)}
                                            title="Eliminar Activo"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                            {activos.length === 0 && (
                                <tr>
                                    <td colSpan="7" style={{ padding: '3rem', textAlign: 'center', color: 'var(--text-muted)' }}>
                                        No hay activos registrados. Registre su primer bien para comenzar el control.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Modal de Nuevo Activo */}
            {showModal && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '1rem' }}>
                    <div className="card" style={{ width: '100%', maxWidth: '500px', padding: '2rem' }}>
                        <h2 style={{ marginBottom: '1.5rem', fontSize: '1.25rem' }}>Registrar Nuevo Activo Fijo</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="input-group">
                                <label className="input-label">Nombre del Activo</label>
                                <input type="text" className="input-field" required value={nuevoActivo.nombre} onChange={e => setNuevoActivo({ ...nuevoActivo, nombre: e.target.value })} placeholder="Ej: Laptop Dell XPS 15" />
                            </div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <div className="input-group">
                                    <label className="input-label">Tipo</label>
                                    <select className="input-field" value={nuevoActivo.tipo} onChange={e => setNuevoActivo({ ...nuevoActivo, tipo: e.target.value })}>
                                        <option value="Mobiliario">Mobiliario y Equipo de Oficina</option>
                                        <option value="Maquinaria">Maquinaria y Equipos</option>
                                        <option value="Vehiculos">Vehículos</option>
                                        <option value="Edificaciones">Edificaciones</option>
                                        <option value="Tecnologia">Equipo de Cómputo</option>
                                    </select>
                                </div>
                                <div className="input-group">
                                    <label className="input-label">Valor de Compra</label>
                                    <input type="number" className="input-field" required value={nuevoActivo.valor} onChange={e => setNuevoActivo({ ...nuevoActivo, valor: e.target.value })} />
                                </div>
                            </div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <div className="input-group">
                                    <label className="input-label">Fecha Compra</label>
                                    <input type="date" className="input-field" required value={nuevoActivo.fechaCompra} onChange={e => setNuevoActivo({ ...nuevoActivo, fechaCompra: e.target.value })} />
                                </div>
                                <div className="input-group">
                                    <label className="input-label">Vida Útil (Años)</label>
                                    <input type="number" className="input-field" required value={nuevoActivo.vidaUtil} onChange={e => setNuevoActivo({ ...nuevoActivo, vidaUtil: e.target.value })} />
                                </div>
                            </div>
                            <div style={{ display: 'flex', gap: '1rem', marginTop: '2rem' }}>
                                <button type="button" className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowModal(false)}>Cancelar</button>
                                <button type="submit" className="btn btn-primary" style={{ flex: 1 }}>Guardar Activo</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            <ConfirmModal
                isOpen={confirmDelete.open}
                onClose={() => setConfirmDelete({ ...confirmDelete, open: false })}
                onConfirm={confirmDeleteAction}
                title="Eliminar Activo Fijo"
                message={`¿Está completamente seguro de que desea eliminar '${confirmDelete.name}'? ⚠️ Esto eliminará el registro histórico y detendrá su depreciación.`}
            />
        </div>
    );
};

export default FixedAssets;

import React, { useMemo } from 'react';
import { useContabilidad } from '../context/ContabilidadContext';
import { TrendingUp, TrendingDown, AlertCircle, CheckCircle, DollarSign, Activity, BarChart2, Shield } from 'lucide-react';

const IndicadoresFinancieros = () => {
    const { asientos } = useContabilidad();

    const formatMoney = (amount) =>
        new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount || 0);
    const formatPct = (val) => `${isNaN(val) || !isFinite(val) ? '—' : val.toFixed(1)}%`;
    const formatRatio = (val) => isNaN(val) || !isFinite(val) ? '—' : val.toFixed(2);

    const calculos = useMemo(() => {
        const saldos = {};
        asientos.forEach(a => {
            (a.detalles || []).forEach(d => {
                if (!d.cuentaId) return;
                if (!saldos[d.cuentaId]) saldos[d.cuentaId] = 0;
                saldos[d.cuentaId] += (Number(d.debito) || 0) - (Number(d.credito) || 0);
            });
        });

        const s = (codigo) => {
            let total = 0;
            Object.entries(saldos).forEach(([k, v]) => { if (k.startsWith(codigo)) total += v; });
            return Math.abs(total);
        };

        // Balance Sheet items
        const caja = s('1101');
        const cxc = s('1103');
        const inventario = s('1104');
        const activoCorr = s('110');
        const activoFijo = s('12');
        const activoTotal = activoCorr + activoFijo;
        const cxp = s('2101');
        const pasivoCorr = s('210');
        const pasivoLargo = s('220');
        const pasivoTotal = pasivoCorr + pasivoLargo;
        const patrimonio = activoTotal - pasivoTotal;

        // Income Statement items
        let ingresos = 0, costoVentas = 0, gastos = 0;
        asientos.forEach(a => {
            (a.detalles || []).forEach(d => {
                if (!d.cuentaId) return;
                if (d.cuentaId.startsWith('4')) ingresos += (Number(d.credito) || 0);
                if (d.cuentaId.startsWith('5')) costoVentas += (Number(d.debito) || 0);
                if (d.cuentaId.startsWith('6')) gastos += (Number(d.debito) || 0);
            });
        });

        const utilidadBruta = ingresos - costoVentas;
        const utilidadNeta = utilidadBruta - gastos;

        // Ratios
        const razonCorriente = pasivoCorr > 0 ? activoCorr / pasivoCorr : null;
        const pruebaAcida = pasivoCorr > 0 ? (caja + cxc) / pasivoCorr : null;
        const endeudamiento = activoTotal > 0 ? (pasivoTotal / activoTotal) * 100 : null;
        const margenBruto = ingresos > 0 ? (utilidadBruta / ingresos) * 100 : null;
        const margenNeto = ingresos > 0 ? (utilidadNeta / ingresos) * 100 : null;
        const roe = patrimonio > 0 ? (utilidadNeta / patrimonio) * 100 : null;
        const roa = activoTotal > 0 ? (utilidadNeta / activoTotal) * 100 : null;
        const rotInv = costoVentas > 0 && inventario > 0 ? costoVentas / inventario : null;
        const diasCobranza = ingresos > 0 ? (cxc / ingresos) * 365 : null;
        const diasPago = costoVentas > 0 ? (cxp / costoVentas) * 365 : null;

        return {
            kpis: { ingresos, costoVentas, utilidadBruta, gastos, utilidadNeta, activoTotal, pasivoTotal, patrimonio, caja, cxc, inventario, activoCorr, pasivoCorr },
            ratios: { razonCorriente, pruebaAcida, endeudamiento, margenBruto, margenNeto, roe, roa, rotInv, diasCobranza, diasPago }
        };
    }, [asientos]);

    const { kpis, ratios } = calculos;

    const RatioCard = ({ titulo, valor, descripcion, bueno, tipo = 'ratio', umbral, invertido = false }) => {
        const numVal = typeof valor === 'number' ? valor : null;
        let estado = 'neutral';
        if (numVal !== null && umbral !== undefined) {
            const ok = invertido ? numVal < umbral : numVal >= umbral;
            estado = ok ? 'bien' : 'alerta';
        }

        const colores = {
            bien: { bg: 'rgba(16,185,129,0.08)', border: 'var(--success)', dot: 'var(--success)' },
            alerta: { bg: 'rgba(239,68,68,0.08)', border: 'var(--danger)', dot: 'var(--danger)' },
            neutral: { bg: 'var(--bg-card)', border: 'var(--border)', dot: 'var(--text-muted)' }
        };
        const c = colores[estado];

        return (
            <div style={{ background: c.bg, border: `1px solid ${c.border}`, borderRadius: 'var(--radius-md)', padding: '1.25rem', transition: 'all 0.2s' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.5rem' }}>
                    <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{titulo}</span>
                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: c.dot, marginTop: 4 }}></div>
                </div>
                <div style={{ fontSize: '1.75rem', fontWeight: 800, color: estado === 'bien' ? 'var(--success)' : estado === 'alerta' ? 'var(--danger)' : 'var(--text-main)' }}>
                    {numVal === null ? '—' : tipo === 'ratio' ? formatRatio(numVal) : tipo === 'pct' ? formatPct(numVal) : `${Math.round(numVal)} días`}
                </div>
                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '0.35rem', lineHeight: 1.5 }}>{descripcion}</div>
                {bueno && <div style={{ fontSize: '0.7rem', marginTop: '0.3rem', color: 'var(--text-muted)', fontStyle: 'italic' }}>Ideal: {bueno}</div>}
            </div>
        );
    };

    return (
        <div className="animate-up">
            <div style={{ marginBottom: '2rem' }}>
                <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Indicadores Financieros</h1>
                <p style={{ color: 'var(--text-muted)' }}>Análisis integral de la salud financiera de tu empresa con ratios clave.</p>
            </div>

            {/* KPIs Principales */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.25rem', marginBottom: '2rem' }}>
                {[
                    { label: 'Ingresos Totales', val: kpis.ingresos, icon: <TrendingUp size={20} color="var(--success)" />, color: 'var(--success)' },
                    { label: 'Costo de Ventas', val: kpis.costoVentas, icon: <TrendingDown size={20} color="var(--danger)" />, color: 'var(--danger)' },
                    { label: 'Utilidad Bruta', val: kpis.utilidadBruta, icon: <DollarSign size={20} color="var(--primary)" />, color: 'var(--primary)' },
                    { label: 'Utilidad Neta', val: kpis.utilidadNeta, icon: <Activity size={20} color={kpis.utilidadNeta >= 0 ? 'var(--success)' : 'var(--danger)'} />, color: kpis.utilidadNeta >= 0 ? 'var(--success)' : 'var(--danger)' },
                ].map(k => (
                    <div key={k.label} className="card" style={{ padding: '1.5rem' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
                            <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>{k.label}</span>
                            {k.icon}
                        </div>
                        <div style={{ fontSize: '1.5rem', fontWeight: 800, color: k.color }}>{formatMoney(k.val)}</div>
                    </div>
                ))}
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem', marginBottom: '2rem' }}>
                {/* Balance Summary */}
                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 700, marginBottom: '1.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Shield size={18} color="var(--primary)" /> Resumen del Balance
                    </h3>
                    {[
                        { label: 'Activo Total', val: kpis.activoTotal, color: 'var(--primary)' },
                        { label: 'Pasivo Total', val: kpis.pasivoTotal, color: 'var(--danger)' },
                        { label: 'Patrimonio', val: kpis.patrimonio, color: 'var(--success)' },
                        { label: 'Caja y Banco', val: kpis.caja, color: 'var(--text-main)' },
                        { label: 'Cuentas por Cobrar', val: kpis.cxc, color: 'var(--text-main)' },
                        { label: 'Inventario', val: kpis.inventario, color: 'var(--text-main)' },
                    ].map((item, i) => (
                        <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.6rem 0', borderBottom: i < 5 ? '1px solid var(--border)' : 'none' }}>
                            <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>{item.label}</span>
                            <span style={{ fontWeight: 700, color: item.color }}>{formatMoney(item.val)}</span>
                        </div>
                    ))}
                </div>

                {/* Semetría Visual */}
                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 700, marginBottom: '1.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <BarChart2 size={18} color="var(--primary)" /> Estructura Financiera
                    </h3>
                    {kpis.activoTotal > 0 ? (
                        <>
                            {[
                                { label: 'Activo Corriente', val: kpis.activoCorr, total: kpis.activoTotal, color: '#3b82f6' },
                                { label: 'Activo Fijo', val: kpis.activoTotal - kpis.activoCorr, total: kpis.activoTotal, color: '#2563eb' },
                                { label: 'Pasivo Corriente', val: kpis.pasivoCorr, total: kpis.activoTotal, color: '#ef4444' },
                                { label: 'Pasivo LP', val: kpis.pasivoTotal - kpis.pasivoCorr, total: kpis.activoTotal, color: '#dc2626' },
                                { label: 'Patrimonio', val: Math.max(0, kpis.patrimonio), total: kpis.activoTotal, color: '#10b981' },
                            ].map(item => {
                                const pct = item.total > 0 ? (item.val / item.total) * 100 : 0;
                                return (
                                    <div key={item.label} style={{ marginBottom: '0.75rem' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.2rem' }}>
                                            <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{item.label}</span>
                                            <span style={{ fontSize: '0.8rem', fontWeight: 600 }}>{pct.toFixed(1)}%</span>
                                        </div>
                                        <div style={{ height: '8px', background: 'var(--background)', borderRadius: '4px', overflow: 'hidden' }}>
                                            <div style={{ width: `${Math.min(100, pct)}%`, height: '100%', background: item.color, borderRadius: '4px', transition: 'width 0.6s ease' }}></div>
                                        </div>
                                    </div>
                                );
                            })}
                        </>
                    ) : (
                        <div style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '2rem' }}>Registra asientos para ver la estructura.</div>
                    )}
                </div>
            </div>

            {/* Ratios por categoría */}
            <div style={{ marginBottom: '1.5rem' }}>
                <h2 style={{ fontWeight: 700, fontSize: '1.125rem', marginBottom: '1rem' }}>🔵 Ratios de Liquidez</h2>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.25rem' }}>
                    <RatioCard titulo="Razón Corriente" valor={ratios.razonCorriente} tipo="ratio" descripcion="Activo corriente / Pasivo corriente. Capacidad de pago a corto plazo." bueno="≥ 1.5" umbral={1.5} />
                    <RatioCard titulo="Prueba Ácida" valor={ratios.pruebaAcida} tipo="ratio" descripcion="(Caja + CxC) / Pasivo corriente. Liquidez sin inventario." bueno="≥ 1.0" umbral={1.0} />
                    <RatioCard titulo="Días de Cobranza" valor={ratios.diasCobranza} tipo="dias" descripcion="Promedio de días que tardan los clientes en pagar." bueno="< 45 días" umbral={45} invertido />
                </div>
            </div>

            <div style={{ marginBottom: '1.5rem' }}>
                <h2 style={{ fontWeight: 700, fontSize: '1.125rem', marginBottom: '1rem' }}>🟢 Ratios de Rentabilidad</h2>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.25rem' }}>
                    <RatioCard titulo="Margen Bruto" valor={ratios.margenBruto} tipo="pct" descripcion="(Ingreso - Costo) / Ingreso × 100." bueno="> 30%" umbral={30} />
                    <RatioCard titulo="Margen Neto" valor={ratios.margenNeto} tipo="pct" descripcion="Utilidad neta / Ingresos × 100." bueno="> 10%" umbral={10} />
                    <RatioCard titulo="ROE" valor={ratios.roe} tipo="pct" descripcion="Retorno sobre Patrimonio." bueno="> 15%" umbral={15} />
                    <RatioCard titulo="ROA" valor={ratios.roa} tipo="pct" descripcion="Retorno sobre Activos." bueno="> 5%" umbral={5} />
                </div>
            </div>

            <div style={{ marginBottom: '2rem' }}>
                <h2 style={{ fontWeight: 700, fontSize: '1.125rem', marginBottom: '1rem' }}>🔴 Ratios de Endeudamiento y Eficiencia</h2>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.25rem' }}>
                    <RatioCard titulo="Endeudamiento" valor={ratios.endeudamiento} tipo="pct" descripcion="Pasivo Total / Activo Total × 100. Proporción financiada con deuda." bueno="< 50%" umbral={50} invertido />
                    <RatioCard titulo="Rotación de Inventario" valor={ratios.rotInv} tipo="ratio" descripcion="Costo de Ventas / Inventario. Cuántas veces rota el inventario en el año." bueno="> 4x" umbral={4} />
                    <RatioCard titulo="Días de Pago" valor={ratios.diasPago} tipo="dias" descripcion="Promedio de días para pagar a proveedores." bueno="30-60 días" />
                </div>
            </div>

            {/* Footer Disclaimer */}
            <div style={{ padding: '1rem 1.5rem', background: 'var(--primary-light)', borderRadius: 'var(--radius-md)', fontSize: '0.8rem', color: 'var(--primary)' }}>
                ℹ️ Los indicadores se calculan automáticamente a partir de los asientos contables registrados. Los umbrales son referencias generales y pueden variar por industria.
            </div>
        </div>
    );
};

export default IndicadoresFinancieros;

import React, { useState } from 'react';
import { useJuridico } from '../context/JuridicoContext';
import { FileText, Scale, Shield, AlertTriangle, Plus, Calendar, X, ExternalLink, Clock } from 'lucide-react';

const TABS = ['Contratos', 'Demandas Activas', 'Documentos Legales'];

const diasHasta = (fecha) => {
    if (!fecha) return null;
    const diff = Math.ceil((new Date(fecha) - new Date()) / (1000 * 60 * 60 * 24));
    return diff;
};

const Juridico = () => {
    const { contratos, demandas, documentos, addContrato, updateContrato, addDemanda, updateDemanda, addDocumento } = useJuridico();
    const [tab, setTab] = useState(0);
    const [modal, setModal] = useState(false);

    const formInit = { tipo: 'Servicio', descripcion: '', contraparte: '', monto: '', fechaInicio: '', fechaFin: '', alertaDias: 30 };
    const [form, setForm] = useState(formInit);
    const s = k => e => setForm({ ...form, [k]: e.target.value });

    const f = v => new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP', maximumFractionDigits: 0 }).format(Number(v) || 0);
    const porVencer = contratos.filter(c => { const d = diasHasta(c.fechaFin); return d !== null && d >= 0 && d <= 60; }).length;
    const demActivas = demandas.filter(d => d.estado !== 'Cerrada').length;
    const montoRiesgo = demandas.filter(d => d.estado !== 'Cerrada').reduce((acc, d) => acc + Number(d.monto || 0), 0);

    const estadoContratoColor = (est) => est === 'Vigente' ? 'var(--success)' : est === 'Por Vencer' ? 'var(--warning)' : 'var(--danger)';

    return (
        <div className="animate-up">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '2rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Gestión Jurídica</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Contratos, demandas, poderes notariales y documentos legales</p>
                </div>
                <button className="btn btn-primary" onClick={() => setModal(true)}><Plus size={16} /> Nuevo Contrato</button>
            </div>

            {/* KPIs */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.25rem', marginBottom: '2rem' }}>
                {[
                    { label: 'Contratos Vigentes', value: contratos.filter(c => c.estado === 'Vigente').length, icon: <FileText size={22} />, color: 'var(--primary)', bg: 'var(--primary-light)' },
                    { label: 'Por Vencer (60 días)', value: porVencer, icon: <Clock size={22} />, color: 'var(--warning)', bg: 'rgba(245,158,11,0.1)' },
                    { label: 'Demandas Activas', value: demActivas, icon: <Scale size={22} />, color: 'var(--danger)', bg: 'rgba(239,68,68,0.1)' },
                    { label: 'Monto en Riesgo', value: f(montoRiesgo), icon: <AlertTriangle size={22} />, color: '#dc2626', bg: 'rgba(220,38,38,0.1)' },
                ].map((k, i) => (
                    <div key={i} className="card" style={{ display: 'flex', gap: '1rem', alignItems: 'center', padding: '1.25rem' }}>
                        <div style={{ width: 48, height: 48, borderRadius: '12px', background: k.bg, color: k.color, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>{k.icon}</div>
                        <div><div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{k.label}</div><div style={{ fontSize: '1.15rem', fontWeight: 800, color: k.color }}>{k.value}</div></div>
                    </div>
                ))}
            </div>

            <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
                <div style={{ display: 'flex', borderBottom: '2px solid var(--border)' }}>
                    {TABS.map((t, i) => (
                        <button key={i} onClick={() => setTab(i)} style={{ padding: '1rem 1.5rem', fontWeight: 600, fontSize: '0.875rem', borderBottom: tab === i ? '2px solid var(--primary)' : 'none', color: tab === i ? 'var(--primary)' : 'var(--text-muted)', background: 'none', cursor: 'pointer', marginBottom: '-2px' }}>{t}</button>
                    ))}
                </div>
                <div style={{ padding: '1.5rem' }}>
                    {tab === 0 && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                            {contratos.map(c => {
                                const dias = diasHasta(c.fechaFin);
                                return (
                                    <div key={c.id} style={{ padding: '1.25rem', background: 'var(--background)', borderRadius: '12px', borderLeft: `4px solid ${estadoContratoColor(c.estado)}` }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                                            <div>
                                                <span style={{ fontSize: '0.75rem', color: 'var(--primary)', fontWeight: 700 }}>{c.numero}</span>
                                                <div style={{ fontWeight: 700, fontSize: '0.95rem', marginTop: '0.15rem' }}>{c.descripcion}</div>
                                                <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Contraparte: <strong>{c.contraparte}</strong></div>
                                            </div>
                                            <div style={{ textAlign: 'right' }}>
                                                <span className="badge" style={{ background: `${estadoContratoColor(c.estado)}20`, color: estadoContratoColor(c.estado) }}>{c.estado}</span>
                                                {dias !== null && dias <= 60 && dias >= 0 && (
                                                    <div style={{ fontSize: '0.75rem', color: 'var(--warning)', marginTop: '0.4rem', fontWeight: 700 }}>⚠️ Vence en {dias} días</div>
                                                )}
                                            </div>
                                        </div>
                                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '0.75rem', fontSize: '0.8rem' }}>
                                            <div><span style={{ color: 'var(--text-muted)' }}>Tipo: </span><strong>{c.tipo}</strong></div>
                                            <div><span style={{ color: 'var(--text-muted)' }}>Monto: </span><strong style={{ color: 'var(--primary)' }}>{f(c.monto)}</strong></div>
                                            <div><span style={{ color: 'var(--text-muted)' }}>Inicio: </span><strong>{c.fechaInicio}</strong></div>
                                            <div><span style={{ color: 'var(--text-muted)' }}>Fin: </span><strong>{c.fechaFin || 'Indefinido'}</strong></div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {tab === 1 && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {demandas.map(d => (
                                <div key={d.id} style={{ padding: '1.25rem', background: 'var(--background)', borderRadius: '12px', borderLeft: `4px solid ${d.tipo === 'Cobro Judicial' ? 'var(--primary)' : 'var(--danger)'}` }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
                                        <div>
                                            <span style={{ fontSize: '0.75rem', color: 'var(--primary)', fontWeight: 700 }}>{d.numero}</span>
                                            <div style={{ fontWeight: 700, marginTop: '0.15rem' }}>{d.descripcion}</div>
                                        </div>
                                        <span className="badge badge-info">{d.tipo}</span>
                                    </div>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '0.75rem', fontSize: '0.8rem', marginBottom: '0.75rem' }}>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Demandante: </span><strong>{d.demandante}</strong></div>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Demandado: </span><strong>{d.demandado}</strong></div>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Monto: </span><strong style={{ color: 'var(--danger)' }}>{f(d.monto)}</strong></div>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Próxima: </span><strong>{d.proxima}</strong></div>
                                    </div>
                                    <div style={{ display: 'flex', gap: '1.5rem', fontSize: '0.8rem' }}>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Tribunal: </span>{d.tribunal}</div>
                                        <div><span style={{ color: 'var(--text-muted)' }}>Abogado: </span><strong>{d.abogado}</strong></div>
                                        <div style={{ marginLeft: 'auto' }}><span className="badge" style={{ background: d.estado === 'En Proceso' ? 'rgba(37,99,235,0.1)' : d.estado === 'Nuevo' ? 'rgba(245,158,11,0.1)' : 'rgba(16,185,129,0.1)', color: d.estado === 'En Proceso' ? 'var(--primary)' : d.estado === 'Nuevo' ? 'var(--warning)' : 'var(--success)' }}>{d.estado}</span></div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}

                    {tab === 2 && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                            {documentos.map(doc => {
                                const dias = diasHasta(doc.vencimiento);
                                return (
                                    <div key={doc.id} style={{ display: 'grid', gridTemplateColumns: '1fr 2fr 1fr 1fr 1fr 100px', gap: '1rem', alignItems: 'center', padding: '1rem', background: 'var(--background)', borderRadius: '10px' }}>
                                        <div><span className="badge badge-info" style={{ fontSize: '0.75rem' }}>{doc.tipo}</span></div>
                                        <div>
                                            <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{doc.descripcion}</div>
                                            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Notario: {doc.notario}</div>
                                        </div>
                                        <div style={{ fontSize: '0.8rem' }}><span style={{ color: 'var(--text-muted)' }}>Beneficiario: </span>{doc.beneficiario}</div>
                                        <div style={{ fontSize: '0.8rem' }}>{doc.fecha}</div>
                                        <div style={{ fontSize: '0.8rem' }}>
                                            {doc.vencimiento ? (
                                                <span style={{ color: dias !== null && dias <= 30 ? 'var(--warning)' : 'var(--text-muted)' }}>{doc.vencimiento} {dias !== null && dias <= 30 && `(${dias}d)`}</span>
                                            ) : 'Sin vencimiento'}
                                        </div>
                                        <span className="badge" style={{ background: doc.estado === 'Vigente' ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)', color: doc.estado === 'Vigente' ? 'var(--success)' : 'var(--danger)' }}>{doc.estado}</span>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>

            {/* Modal Contrato */}
            {modal && (
                <div className="modal-overlay">
                    <div className="card" style={{ width: '100%', maxWidth: '560px', padding: 0, overflowY: 'auto', maxHeight: '90vh' }}>
                        <div style={{ padding: '1.25rem 1.5rem', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, background: 'var(--bg-card)', zIndex: 1 }}>
                            <h3 style={{ fontWeight: 700 }}>Nuevo Contrato</h3>
                            <button onClick={() => setModal(false)}><X size={18} /></button>
                        </div>
                        <form onSubmit={e => { e.preventDefault(); addContrato(form); setForm(formInit); setModal(false); }} style={{ padding: '1.5rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div><label className="input-label">Tipo *</label>
                                <select required className="input-field" value={form.tipo} onChange={s('tipo')}>
                                    {['Servicio', 'Arrendamiento', 'Consultoría', 'Proveedor', 'Laboral', 'Otro'].map(t => <option key={t}>{t}</option>)}
                                </select>
                            </div>
                            <div><label className="input-label">Monto Contractual</label><input type="number" className="input-field" value={form.monto} onChange={s('monto')} placeholder="120000" /></div>
                            <div style={{ gridColumn: '1/-1' }}><label className="input-label">Descripción *</label><input required className="input-field" value={form.descripcion} onChange={s('descripcion')} placeholder="Describe el objeto del contrato" /></div>
                            <div><label className="input-label">Contraparte *</label><input required className="input-field" value={form.contraparte} onChange={s('contraparte')} placeholder="Nombre empresa/persona" /></div>
                            <div><label className="input-label">Alerta (días antes)</label><input type="number" className="input-field" value={form.alertaDias} onChange={s('alertaDias')} /></div>
                            <div><label className="input-label">Fecha de Inicio *</label><input required type="date" className="input-field" value={form.fechaInicio} onChange={s('fechaInicio')} /></div>
                            <div><label className="input-label">Fecha de Fin</label><input type="date" className="input-field" value={form.fechaFin} onChange={s('fechaFin')} /></div>
                            <div style={{ gridColumn: '1/-1', display: 'flex', justifyContent: 'flex-end', gap: '0.75rem', marginTop: '0.5rem' }}>
                                <button type="button" className="btn btn-secondary" onClick={() => setModal(false)}>Cancelar</button>
                                <button type="submit" className="btn btn-primary">💾 Guardar Contrato</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Juridico;

import React, { useState } from 'react';
import { useNotas } from '../context/NotasContext';
import { useContactos } from '../context/ContactosContext';
import { useCuentas } from '../context/CuentasContext';
import { useFacturacion } from '../context/FacturacionContext';
import { FileX, FilePlus, Trash2, Plus } from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const NotasCreditoDebito = () => {
    const { notas, registrarNota, eliminarNota } = useNotas();
    const { contactos } = useContactos();
    const { cuentas } = useCuentas();
    const { facturas } = useFacturacion();

    const [showModal, setShowModal] = useState(false);
    const [confirmDelete, setConfirmDelete] = useState({ open: false, id: null });
    const [tipoNota, setTipoNota] = useState('credito');
    const [filtro, setFiltro] = useState('todos');

    const [form, setForm] = useState({
        tipoNota: 'credito',
        contactoId: '',
        facturaRefId: '',
        ncf: '',
        descripcion: '',
        subtotal: '',
        itbis: '',
    });

    const contacts = contactos;
    const cuentasIngreso = cuentas.filter(c => c.codigo?.startsWith('4'));
    const cuentasGasto = cuentas.filter(c => c.codigo?.startsWith('5') || c.codigo?.startsWith('6'));
    const cuentasDeudor = cuentas.filter(c => c.codigo?.startsWith('11'));

    const handleChange = (e) => setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));

    const handleRefInvoiceChange = (e) => {
        const invId = e.target.value;
        if (!invId) return;

        const inv = facturas.find(f => f.id === invId);
        if (!inv) return;

        // Intentar encontrar el contacto ID por RNC o Nombre
        const contacto = contacts.find(c => c.rnc === inv.clienteRnc || c.nombre === inv.clienteNombre);

        setForm(prev => ({
            ...prev,
            contactoId: contacto?.id || '',
            facturaRefId: inv.ncf || inv.numeroInterno,
            subtotal: inv.subtotal.toString(),
            itbis: inv.itbis.toString(),
            descripcion: `Devolución/Ajuste de Factura ${inv.ncf || inv.numeroInterno}`
        }));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        const contacto = contacts.find(c => c.id === form.contactoId);
        const subtotal = parseFloat(form.subtotal) || 0;
        const itbisVal = parseFloat(form.itbis) || 0;

        registrarNota({
            ...form,
            tipoNota: tipoNota,
            contactoNombre: contacto?.nombre || 'Sin contacto',
            subtotal,
            itbis: itbisVal,
            total: subtotal + itbisVal,
        });

        setShowModal(false);
        setForm({ tipoNota: 'credito', contactoId: '', facturaRefId: '', ncf: '', descripcion: '', subtotal: '', itbis: '' });
    };

    const formatMoney = (amount) =>
        new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(amount || 0);

    const notasFiltradas = filtro === 'todos' ? notas : notas.filter(n => n.tipoNota === filtro);

    return (
        <div className="animate-up">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Notas de Crédito y Débito</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Gestiona devoluciones de ventas y ajustes sobre facturas emitidas.</p>
                </div>
                <div style={{ display: 'flex', gap: '1rem' }}>
                    <button className="btn" style={{ background: 'rgba(239,68,68,0.1)', color: 'var(--danger)' }}
                        onClick={() => { setTipoNota('debito'); setShowModal(true); }}>
                        <FilePlus size={18} /> Nueva Nota de Débito
                    </button>
                    <button className="btn btn-primary"
                        onClick={() => { setTipoNota('credito'); setShowModal(true); }}>
                        <FileX size={18} /> Nueva Nota de Crédito
                    </button>
                </div>
            </div>

            {/* Filtros */}
            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1.5rem' }}>
                {['todos', 'credito', 'debito'].map(f => (
                    <button key={f} className="btn btn-secondary"
                        style={{ background: filtro === f ? 'var(--primary)' : undefined, color: filtro === f ? 'white' : undefined, padding: '0.5rem 1.25rem' }}
                        onClick={() => setFiltro(f)}>
                        {f === 'todos' ? 'Todas' : f === 'credito' ? 'Notas de Crédito' : 'Notas de Débito'}
                    </button>
                ))}
            </div>

            <div className="card">
                <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                        <thead>
                            <tr style={{ background: 'var(--background)', fontSize: '0.8rem' }}>
                                <th style={{ padding: '1rem', textAlign: 'left' }}>Número</th>
                                <th style={{ padding: '1rem', textAlign: 'left' }}>Fecha</th>
                                <th style={{ padding: '1rem', textAlign: 'left' }}>Tipo</th>
                                <th style={{ padding: '1rem', textAlign: 'left' }}>Contacto</th>
                                <th style={{ padding: '1rem', textAlign: 'left' }}>Descripción</th>
                                <th style={{ padding: '1rem', textAlign: 'right' }}>Subtotal</th>
                                <th style={{ padding: '1rem', textAlign: 'right' }}>ITBIS</th>
                                <th style={{ padding: '1rem', textAlign: 'right' }}>Total</th>
                                <th style={{ padding: '1rem' }}></th>
                            </tr>
                        </thead>
                        <tbody>
                            {notasFiltradas.length === 0 ? (
                                <tr><td colSpan={9} style={{ padding: '3rem', textAlign: 'center', color: 'var(--text-muted)' }}>No hay notas registradas.</td></tr>
                            ) : (
                                [...notasFiltradas].reverse().map(n => (
                                    <tr key={n.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                        <td style={{ padding: '1rem', fontWeight: 700 }}>{n.numeroInterno}</td>
                                        <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{new Date(n.fechaRegistro).toLocaleDateString('es-DO')}</td>
                                        <td style={{ padding: '1rem' }}>
                                            <span style={{
                                                padding: '0.2rem 0.65rem', borderRadius: '1rem', fontSize: '0.75rem', fontWeight: 700,
                                                background: n.tipoNota === 'credito' ? 'rgba(16,185,129,0.12)' : 'rgba(239,68,68,0.12)',
                                                color: n.tipoNota === 'credito' ? 'var(--success)' : 'var(--danger)'
                                            }}>
                                                {n.tipoNota === 'credito' ? 'Crédito' : 'Débito'}
                                            </span>
                                        </td>
                                        <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{n.contactoNombre}</td>
                                        <td style={{ padding: '1rem', fontSize: '0.875rem', maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis' }}>{n.descripcion}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right' }}>{formatMoney(n.subtotal)}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right' }}>{formatMoney(n.itbis)}</td>
                                        <td style={{ padding: '1rem', textAlign: 'right', fontWeight: 700 }}>{formatMoney(n.total)}</td>
                                        <td style={{ padding: '1rem' }}>
                                            <button onClick={() => setConfirmDelete({ open: true, id: n.id })}
                                                style={{ color: 'var(--danger)', background: 'none', border: 'none', cursor: 'pointer' }}>
                                                <Trash2 size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {showModal && (
                <div className="modal-overlay">
                    <div className="card" style={{ width: '100%', maxWidth: '580px', padding: 0 }}>
                        <div style={{ padding: '1.5rem', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h2 style={{ fontSize: '1.125rem', fontWeight: 700 }}>
                                {tipoNota === 'credito' ? '📄 Nueva Nota de Crédito' : '📄 Nueva Nota de Débito'}
                            </h2>
                            <button onClick={() => setShowModal(false)} style={{ color: 'var(--text-muted)', background: 'none', border: 'none', cursor: 'pointer', fontSize: '1.5rem' }}>×</button>
                        </div>
                        <form onSubmit={handleSubmit} style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <div className="input-group" style={{ marginBottom: 0 }}>
                                <label className="input-label" style={{ color: 'var(--primary)', fontWeight: 600 }}>🔍 Buscar Factura Original (Opcional)</label>
                                <select className="input-field" onChange={handleRefInvoiceChange} style={{ border: '2px solid var(--primary-light)' }}>
                                    <option value="">-- Seleccionar factura para autocompletar --</option>
                                    {[...facturas].reverse().slice(0, 20).map(f => (
                                        <option key={f.id} value={f.id}>
                                            {f.ncf} | {f.clienteNombre} | {new Date(f.fecha || f.fechaEmision).toLocaleDateString()} | {formatMoney(f.total)}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="input-group" style={{ marginBottom: 0 }}>
                                <label className="input-label">Contacto</label>
                                <select name="contactoId" className="input-field" value={form.contactoId} onChange={handleChange} required>
                                    <option value="">-- Seleccionar --</option>
                                    {contacts.map(c => <option key={c.id} value={c.id}>{c.nombre}</option>)}
                                </select>
                            </div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">NCF de la Nota</label>
                                    <input name="ncf" className="input-field" value={form.ncf} onChange={handleChange} placeholder="Dejar vacío para auto-generar" />
                                    <span style={{ fontSize: '0.65rem', color: 'var(--text-muted)' }}>* Se usará el siguiente número del rango activo.</span>
                                </div>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">NCF Factura Original</label>
                                    <input name="facturaRefId" className="input-field" value={form.facturaRefId} onChange={handleChange} placeholder="B0100000001" />
                                </div>
                            </div>
                            <div className="input-group" style={{ marginBottom: 0 }}>
                                <label className="input-label">Descripción / Motivo</label>
                                <input name="descripcion" className="input-field" value={form.descripcion} onChange={handleChange} placeholder="Devolución de mercancía..." required />
                            </div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">Subtotal</label>
                                    <input name="subtotal" type="number" className="input-field" value={form.subtotal} onChange={handleChange} placeholder="0.00" required />
                                </div>
                                <div className="input-group" style={{ marginBottom: 0 }}>
                                    <label className="input-label">ITBIS (18%)</label>
                                    <input name="itbis" type="number" className="input-field" value={form.itbis} onChange={handleChange} placeholder="0.00" />
                                </div>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', paddingTop: '0.5rem' }}>
                                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Cancelar</button>
                                <button type="submit" className="btn btn-primary">Registrar {tipoNota === 'credito' ? 'Nota de Crédito' : 'Nota de Débito'}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <ConfirmModal
                isOpen={confirmDelete.open}
                onClose={() => setConfirmDelete({ open: false, id: null })}
                onConfirm={() => { eliminarNota(confirmDelete.id); setConfirmDelete({ open: false, id: null }); }}
                title="Eliminar Nota"
                message="¿Seguro que desea eliminar esta nota? El asiento contable asociado no se revertirá automáticamente."
            />
        </div>
    );
};

export default NotasCreditoDebito;

import React, { useState, useMemo } from 'react';
import { useSocios } from '../context/SociosContext';
import { useCaja } from '../context/CajaContext';
import { usePrestamos } from '../context/PrestamosContext';
import {
    Search, ChevronLeft, ChevronRight, RefreshCw, X,
    DollarSign, ArrowDownCircle, ArrowUpCircle, Printer,
    CheckCircle2, Plus, Trash2, List, Coins, FileText as FileIcon
} from 'lucide-react';

// ── Helpers ──────────────────────────────────────────────────────────────────
const fmt = (n) => new Intl.NumberFormat('es-DO', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(Number(n) || 0);
const DENOMINATIONS = [2000, 1000, 500, 200, 100, 50, 25, 20, 10, 5, 1, 0.01];

// ═════════════════════════════════════════════════════════════════════════════
// MODAL: Desglose de Efectivo
// ═════════════════════════════════════════════════════════════════════════════
const DesgloseModal = ({ monto, onConfirm, onClose }) => {
    const [cantidades, setCantidades] = useState(() =>
        Object.fromEntries(DENOMINATIONS.map(d => [d, 0]))
    );

    const totalDesglosado = DENOMINATIONS.reduce((sum, d) => sum + d * (cantidades[d] || 0), 0);
    const cambio = Math.max(0, totalDesglosado - monto);

    const handleCant = (den, val) => {
        const v = Math.max(0, parseInt(val) || 0);
        setCantidades(p => ({ ...p, [den]: v }));
    };

    const denLabel = (d) => d < 1 ? 'Ctvs' : d.toLocaleString('es-DO');

    return (
        <div className="modal-overlay" style={{ zIndex: 1100 }}>
            <div className="card glass" style={{ width: '520px', padding: 0, overflow: 'hidden', boxShadow: '0 24px 64px rgba(0,0,0,0.25)' }}>
                {/* Header */}
                <div style={{ background: 'linear-gradient(135deg, var(--primary), #1e40af)', padding: '0.75rem 1.25rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ color: 'white', fontWeight: 800, fontSize: '0.95rem', letterSpacing: '1px', textTransform: 'uppercase' }}>
                        Desglose de Efectivo
                    </span>
                    <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', borderRadius: '6px', padding: '0.25rem', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <X size={16} color="white" />
                    </button>
                </div>

                <div style={{ padding: '1rem', display: 'grid', gridTemplateColumns: '1fr auto', gap: '1rem' }}>
                    {/* Tabla denominaciones */}
                    <div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.25rem', padding: '0.4rem 0.5rem', background: 'var(--primary)', borderRadius: 'var(--radius-sm)', marginBottom: '0.25rem' }}>
                            {['Desglose', 'Cant.', 'Monto'].map(h => (
                                <span key={h} style={{ color: 'white', fontSize: '0.72rem', fontWeight: 800, textTransform: 'uppercase' }}>{h}</span>
                            ))}
                        </div>
                        <div style={{ maxHeight: '320px', overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}>
                            {DENOMINATIONS.map(den => (
                                <div key={den} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.25rem', padding: '0.25rem 0.5rem', borderBottom: '1px solid var(--border-light)', alignItems: 'center' }}>
                                    <span style={{ fontSize: '0.85rem', fontWeight: 700, color: 'var(--primary)' }}>
                                        {den === 0.01 ? 'Ctvs' : `RD$${denLabel(den)}`}
                                    </span>
                                    <input
                                        type="number"
                                        min="0"
                                        className="input-field"
                                        style={{ height: '1.8rem', fontSize: '0.82rem', padding: '0 0.4rem', width: '100%' }}
                                        value={cantidades[den] || ''}
                                        onChange={e => handleCant(den, e.target.value)}
                                    />
                                    <span style={{ fontSize: '0.82rem', fontWeight: 600, textAlign: 'right', color: cantidades[den] > 0 ? 'var(--success)' : 'var(--text-muted)' }}>
                                        {fmt(den * (cantidades[den] || 0))}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Panel derecho */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', minWidth: '150px', paddingTop: '1.5rem' }}>
                        <div style={{ background: 'var(--primary-light)', border: '1px solid var(--primary)', borderRadius: 'var(--radius-md)', padding: '0.75rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--primary)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Monto a Cobrar</div>
                            <div style={{ fontSize: '1.4rem', fontWeight: 800, color: 'var(--primary)' }}>{fmt(monto)}</div>
                        </div>
                        <div style={{ background: 'rgba(16,185,129,0.07)', border: '1px solid var(--success)', borderRadius: 'var(--radius-md)', padding: '0.75rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--success)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Efectivo Desglosado</div>
                            <div style={{ fontSize: '1.4rem', fontWeight: 800, color: 'var(--success)' }}>{fmt(totalDesglosado)}</div>
                        </div>
                        <div style={{ background: cambio > 0 ? 'rgba(245,158,11,0.07)' : 'var(--bg-secondary)', border: `1px solid ${cambio > 0 ? 'var(--warning)' : 'var(--border)'}`, borderRadius: 'var(--radius-md)', padding: '0.75rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '0.72rem', fontWeight: 700, color: cambio > 0 ? 'var(--warning)' : 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>Cambio</div>
                            <div style={{ fontSize: '1.4rem', fontWeight: 800, color: cambio > 0 ? 'var(--warning)' : 'var(--text-muted)' }}>{fmt(cambio)}</div>
                        </div>
                    </div>
                </div>

                {/* Botones */}
                <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end', padding: '0.75rem 1rem', borderTop: '1px solid var(--border)', background: 'var(--bg-secondary)' }}>
                    <button className="btn btn-secondary" onClick={onClose} style={{ gap: '0.4rem' }}>
                        <X size={14} /> Cancelar
                    </button>
                    <button className="btn btn-primary" onClick={() => onConfirm({ cantidades, totalDesglosado, cambio })} style={{ gap: '0.4rem', background: 'var(--success)', borderColor: 'var(--success)' }}>
                        <CheckCircle2 size={14} /> OK — Confirmar
                    </button>
                </div>
            </div>
        </div>
    );
};

// ═════════════════════════════════════════════════════════════════════════════
// MODAL: Pagos Mixtos
// ═════════════════════════════════════════════════════════════════════════════
const BANCOS = ['BHD León', 'Banco Popular', 'Banreservas', 'Scotiabank', 'Banco BDI', 'Apap', 'Otro'];

const PagosMixtosModal = ({ monto, onConfirm, onClose }) => {
    const [items, setItems] = useState([{ id: 1, tipo: 'Cheque', monto: 0, referencia: '', banco: '' }]);
    const [efectivo, setEfectivo] = useState(monto);

    const addItem = () => setItems(p => [...p, { id: Date.now(), tipo: 'Cheque', monto: 0, referencia: '', banco: '' }]);
    const removeItem = (id) => setItems(p => p.filter(i => i.id !== id));
    const updateItem = (id, field, val) => setItems(p => p.map(i => i.id === id ? { ...i, [field]: val } : i));

    const totales = items.reduce((acc, i) => {
        const m = Number(i.monto) || 0;
        if (i.tipo === 'Cheque') acc.cheques += m;
        if (i.tipo === 'Tarjeta') acc.tarjetas += m;
        if (i.tipo === 'Transferencias') acc.transferencias += m;
        return acc;
    }, { cheques: 0, tarjetas: 0, transferencias: 0 });

    const totalDesglosado = efectivo + totales.cheques + totales.tarjetas + totales.transferencias;

    return (
        <div className="modal-overlay" style={{ zIndex: 1100 }}>
            <div className="card glass" style={{ width: '600px', padding: 0, overflow: 'hidden', boxShadow: '0 24px 64px rgba(0,0,0,0.25)' }}>
                {/* Header */}
                <div style={{ background: 'linear-gradient(135deg, var(--primary), #1e40af)', padding: '0.75rem 1.25rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ color: 'white', fontWeight: 800, letterSpacing: '1px', textTransform: 'uppercase' }}>Pagos Mixtos</span>
                    <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', borderRadius: '6px', padding: '0.25rem', cursor: 'pointer' }}>
                        <X size={16} color="white" />
                    </button>
                </div>

                <div style={{ padding: '1rem' }}>
                    {/* Cabecera */}
                    <div style={{ display: 'grid', gridTemplateColumns: '140px 90px 1fr 1fr 60px', gap: '0.5rem', padding: '0.35rem 0.5rem', background: 'var(--primary)', borderRadius: 'var(--radius-sm)', marginBottom: '0.25rem' }}>
                        {['Tipo', 'Monto', 'Referencia', 'Banco', 'Acc.'].map(h => (
                            <span key={h} style={{ color: 'white', fontSize: '0.72rem', fontWeight: 800, textTransform: 'uppercase' }}>{h}</span>
                        ))}
                    </div>

                    {/* Filas dinámicas */}
                    <div style={{ maxHeight: '200px', overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)', marginBottom: '0.75rem' }}>
                        {items.map((item) => (
                            <div key={item.id} style={{ display: 'grid', gridTemplateColumns: '140px 90px 1fr 1fr 60px', gap: '0.5rem', padding: '0.35rem 0.5rem', borderBottom: '1px solid var(--border-light)', alignItems: 'center' }}>
                                <select className="input-field" style={{ height: '1.9rem', fontSize: '0.82rem', padding: '0 0.35rem' }}
                                    value={item.tipo} onChange={e => updateItem(item.id, 'tipo', e.target.value)}>
                                    {['Cheque', 'Tarjeta', 'Transferencias'].map(t => <option key={t}>{t}</option>)}
                                </select>
                                <input type="number" min="0" className="input-field" style={{ height: '1.9rem', fontSize: '0.82rem', padding: '0 0.35rem' }}
                                    value={item.monto} onChange={e => updateItem(item.id, 'monto', e.target.value)} />
                                <input type="text" className="input-field" style={{ height: '1.9rem', fontSize: '0.82rem', padding: '0 0.35rem' }}
                                    placeholder="Ref..." value={item.referencia} onChange={e => updateItem(item.id, 'referencia', e.target.value)} />
                                <select className="input-field" style={{ height: '1.9rem', fontSize: '0.82rem', padding: '0 0.35rem' }}
                                    value={item.banco} onChange={e => updateItem(item.id, 'banco', e.target.value)}>
                                    <option value=""></option>
                                    {BANCOS.map(b => <option key={b}>{b}</option>)}
                                </select>
                                <div style={{ display: 'flex', gap: '0.25rem' }}>
                                    <button onClick={addItem} style={{ background: 'var(--success)', color: 'white', border: 'none', borderRadius: '6px', width: '24px', height: '24px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Plus size={13} />
                                    </button>
                                    {items.length > 1 && (
                                        <button onClick={() => removeItem(item.id)} style={{ background: 'var(--danger)', color: 'white', border: 'none', borderRadius: '6px', width: '24px', height: '24px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                            <Trash2 size={11} />
                                        </button>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Summary grid */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.5rem', padding: '0.75rem', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-md)', border: '1px solid var(--border)' }}>
                        {[
                            ['Efectivo', efectivo],
                            ['Tarjetas', totales.tarjetas],
                            ['Total a Desglosar', monto],
                            ['Cheques', totales.cheques],
                            ['Transferencia', totales.transferencias],
                            ['Total Desglosado', totalDesglosado],
                        ].map(([label, val]) => (
                            <div key={label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.35rem 0.5rem', background: 'var(--bg-card)', borderRadius: 'var(--radius-sm)', border: '1px solid var(--border-light)' }}>
                                <span style={{ fontSize: '0.78rem', color: 'var(--text-muted)', fontWeight: 600 }}>{label}</span>
                                <span style={{ fontSize: '0.88rem', fontWeight: 800, color: label.includes('Total') ? 'var(--primary)' : 'inherit' }}>{fmt(val)}</span>
                            </div>
                        ))}
                    </div>

                    {/* Efectivo field */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginTop: '0.75rem' }}>
                        <label style={{ fontSize: '0.82rem', fontWeight: 600 }}>Efectivo:</label>
                        <input type="number" min="0" className="input-field" style={{ height: '2rem', fontSize: '0.88rem', width: '140px' }}
                            value={efectivo} onChange={e => setEfectivo(Number(e.target.value) || 0)} />
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end', padding: '0.75rem 1rem', borderTop: '1px solid var(--border)', background: 'var(--bg-secondary)' }}>
                    <button className="btn btn-secondary" onClick={onClose} style={{ gap: '0.4rem' }}>
                        <X size={14} /> Cancelar
                    </button>
                    <button className="btn btn-primary" onClick={() => onConfirm({ items, efectivo, totales, totalDesglosado })} style={{ gap: '0.4rem', background: 'var(--success)', borderColor: 'var(--success)' }}>
                        <CheckCircle2 size={14} /> Aceptar
                    </button>
                </div>
            </div>
        </div>
    );
};

// ═════════════════════════════════════════════════════════════════════════════
// MODAL: Cuotas Pendientes
// ═════════════════════════════════════════════════════════════════════════════
const CuotasPendientesModal = ({ cuotas, onConfirm, onClose }) => {
    const [selectedIds, setSelectedIds] = useState(cuotas.slice(0, 1).map(c => c.id));

    const toggle = (id) => {
        setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    };

    const selectedCuotas = cuotas.filter(c => selectedIds.includes(c.id));
    const totals = selectedCuotas.reduce((acc, c) => ({
        capital: acc.capital + c.capital,
        interes: acc.interes + c.interes,
        mora: acc.mora + c.mora,
        seguro: acc.seguro + c.seguro,
        otros: acc.otros + c.otros,
        total: acc.total + c.total
    }), { capital: 0, interes: 0, mora: 0, seguro: 0, otros: 0, total: 0 });

    return (
        <div className="modal-overlay" style={{ zIndex: 1100 }}>
            <div className="card glass" style={{ width: '850px', padding: 0, overflow: 'hidden', boxShadow: '0 24px 64px rgba(0,0,0,0.25)' }}>
                <div style={{ background: 'var(--primary)', padding: '0.75rem 1.25rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ color: 'white', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1px' }}>Cuotas Pendientes</span>
                    <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', borderRadius: '6px', padding: '0.2rem', cursor: 'pointer' }}>
                        <X size={16} color="white" />
                    </button>
                </div>

                <div style={{ padding: '1rem' }}>
                    <h3 style={{ textAlign: 'center', color: 'var(--primary)', fontSize: '0.9rem', marginBottom: '1rem', fontWeight: 700 }}>Cuotas a Descontar de la Cta. 266 PRESTAMO NORMAL</h3>

                    <div style={{ border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)', overflow: 'hidden' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '40px 100px 1fr 1fr 1fr 1fr 1fr 1fr', background: 'var(--primary)', padding: '0.5rem', gap: '0.5rem' }}>
                            <div />
                            {['Fecha Pago', 'Cap. Pend.', 'Int. Pend.', 'Mora Pend.', 'Seg. Pend.', 'Otros Pend.', 'Total'].map(h => (
                                <span key={h} style={{ fontSize: '0.65rem', fontWeight: 800, color: 'white', textTransform: 'uppercase' }}>{h}</span>
                            ))}
                        </div>
                        <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
                            {cuotas.map(c => (
                                <div key={c.id} style={{ display: 'grid', gridTemplateColumns: '40px 100px 1fr 1fr 1fr 1fr 1fr 1fr', padding: '0.5rem', gap: '0.5rem', borderBottom: '1px solid var(--border-light)', alignItems: 'center', background: selectedIds.includes(c.id) ? 'rgba(34,197,94,0.05)' : 'transparent' }}>
                                    <input type="checkbox" checked={selectedIds.includes(c.id)} onChange={() => toggle(c.id)} style={{ accentColor: 'var(--success)', width: '16px', height: '16px' }} />
                                    <span style={{ fontSize: '0.8rem', fontWeight: 600 }}>{c.fecha}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(c.capital)}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(c.interes)}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(c.mora)}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(c.seguro)}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(c.otros)}</span>
                                    <span style={{ fontSize: '0.8rem', textAlign: 'right', fontWeight: 700 }}>{fmt(c.total)}</span>
                                </div>
                            ))}
                        </div>
                        {/* Totales */}
                        <div style={{ display: 'grid', gridTemplateColumns: '40px 100px 1fr 1fr 1fr 1fr 1fr 1fr', padding: '0.75rem 0.5rem', gap: '0.5rem', background: 'var(--bg-secondary)', fontWeight: 800, borderTop: '2px solid var(--primary)' }}>
                            <span style={{ fontSize: '0.75rem', color: 'var(--success)' }}>Totales</span>
                            <div />
                            <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(totals.capital)}</span>
                            <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(totals.interes)}</span>
                            <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(totals.mora)}</span>
                            <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(totals.seguro)}</span>
                            <span style={{ fontSize: '0.8rem', textAlign: 'right' }}>{fmt(totals.otros)}</span>
                            <span style={{ fontSize: '0.85rem', textAlign: 'right', color: 'var(--primary)' }}>{fmt(totals.total)}</span>
                        </div>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'center', padding: '1rem', borderTop: '1px solid var(--border)', background: 'var(--bg-secondary)' }}>
                    <button className="btn btn-primary" onClick={() => onConfirm(totals)} style={{ background: 'var(--success)', borderColor: 'var(--success)', minWidth: '140px', gap: '0.5rem' }}>
                        <CheckCircle2 size={16} /> OK
                    </button>
                    <button className="btn btn-secondary" onClick={onClose} style={{ minWidth: '140px', gap: '0.5rem' }}>
                        <X size={16} /> Cancel
                    </button>
                </div>
            </div>
        </div>
    );
};

// ═════════════════════════════════════════════════════════════════════════════
// VISTA PRINCIPAL: Pagos en Caja
// ═════════════════════════════════════════════════════════════════════════════
const CUENTA_TYPES = {
    ahorros: 'Ahorros',
    prestamos: 'Préstamos',
    aportacion: 'Aportaciones',
};

const buildCuentas = (socio) => {
    if (!socio) return [];
    const cuentas = [];
    if (socio.ahorros > 0 || socio.ficha)
        cuentas.push({ id: 'aho', numero: socio.codigo, descripcion: 'AHORROS LIBRETA (RETIRABLE)', tipo: 'Ahorros', balance: socio.ahorros || 0, obs: '' });
    if (socio.aportacion > 0)
        cuentas.push({ id: 'apo', numero: (parseInt(socio.codigo?.replace('SOC-', '') || 0) * 6).toString(), descripcion: 'APORTACIONES', tipo: 'Aportaciones', balance: socio.aportacion || 0, obs: '' });
    if (socio.prestamos > 0)
        cuentas.push({ id: 'pre', numero: (parseInt(socio.codigo?.replace('SOC-', '') || 0) * 3).toString().padStart(3, '0'), descripcion: 'PRESTAMO NORMAL', tipo: 'Préstamos', balance: socio.prestamos || 0, obs: '' });
    cuentas.push({ id: 'otros', numero: socio.codigo, descripcion: 'Otras Ingresos', tipo: 'Transacciones Libro Mayor', balance: 0, obs: '' });
    return cuentas;
};

const PagosEnCaja = () => {
    const { socios, actualizarSocio } = useSocios();
    const { agregarRecibo } = useCaja();

    // ── Estado de búsqueda ────────────────────────────────────────────────
    const [busqCodigo, setBusqCodigo] = useState('');
    const [busqNombre, setBusqNombre] = useState('');
    const [busqCedula, setBusqCedula] = useState('');
    const [socioIdx, setSocioIdx] = useState(0);
    const [searched, setSearched] = useState(false);

    // ── Estado de compte seleccionada ─────────────────────────────────────
    const [cuentaSel, setCuentaSel] = useState(null);
    const [monto, setMonto] = useState('');
    const [observacion, setObservacion] = useState('');
    const [formaPago, setFormaPago] = useState('efectivo'); // efectivo | mixto
    const [muestraBalance, setMuestraBalance] = useState(true);

    // ── Modales ────────────────────────────────────────────────────────────
    const [showDesglose, setShowDesglose] = useState(false);
    const [showMixto, setShowMixto] = useState(false);
    const [showRecibo, setShowRecibo] = useState(null);
    const [showCuotas, setShowCuotas] = useState(false);

    // ── Estado de Préstamo ───────────────────────────────────────────────
    const [loanFields, setLoanFields] = useState({
        capital: 0, interes: 0, mora: 0, seguro: 0, comision: 0, otros: 0
    });
    const [ncf, setNcf] = useState('(B02) Factura Consumidor Final');
    const [tipoPago, setTipoPago] = useState('pagar'); // pagar | abonar
    const [saldarPrestamo, setSaldarPrestamo] = useState(false);

    // ── Socios filtrados ──────────────────────────────────────────────────
    const filtrados = useMemo(() => socios.filter(s => {
        const q = v => (v || '').toLowerCase();
        return (
            (!busqCodigo || q(s.codigo).includes(q(busqCodigo))) &&
            (!busqNombre || q(s.nombre).includes(q(busqNombre))) &&
            (!busqCedula || q(s.cedula).includes(q(busqCedula)))
        );
    }), [socios, busqCodigo, busqNombre, busqCedula]);

    const socio = searched && filtrados.length > 0 ? filtrados[socioIdx] : null;
    const cuentas = buildCuentas(socio);
    const cuentaActual = cuentas.find(c => c.id === cuentaSel?.id) || cuentaSel;

    const handleBuscar = () => { setSearched(true); setSocioIdx(0); setCuentaSel(null); setMonto(''); };
    const handleLimpiar = () => { setBusqCodigo(''); setBusqNombre(''); setBusqCedula(''); setSearched(false); setSocioIdx(0); setCuentaSel(null); setMonto(''); setObservacion(''); };
    const handlePrev = () => { if (socioIdx > 0) { setSocioIdx(p => p - 1); setCuentaSel(null); } };
    const handleNext = () => { if (socioIdx < filtrados.length - 1) { setSocioIdx(p => p + 1); setCuentaSel(null); } };

    // Saldos calculados
    const saldoActual = cuentaActual?.balance || 0;
    const pignorado = 0;
    const flotante = 0;
    const embargos = 0;
    const disponible = saldoActual - pignorado - flotante - embargos;

    // ── Depósito / Retiro ──────────────────────────────────────────────────
    const ejecutarTransaccion = (tipo) => {
        const m = parseFloat(monto) || 0;
        if (!m || m <= 0) { alert('Ingrese un monto válido.'); return; }
        if (!cuentaActual) { alert('Seleccione una cuenta.'); return; }
        if (tipo === 'retiro' && m > disponible) { alert('Monto supera el saldo disponible.'); return; }

        const campo = cuentaActual.tipo === 'Ahorros' ? 'ahorros'
            : cuentaActual.tipo === 'Aportaciones' ? 'aportacion'
                : 'prestamos';

        const nuevo = tipo === 'deposito'
            ? saldoActual + m
            : saldoActual - m;

        actualizarSocio(socio.id, { [campo]: nuevo });
        agregarRecibo({
            numero: `REC-${Date.now().toString().slice(-6)}`,
            fecha: new Date().toISOString(),
            cliente: socio.nombre,
            concepto: `${tipo === 'deposito' ? 'Depósito' : 'Retiro'} — ${cuentaActual.descripcion}`,
            monto: m,
            estado: 'Valido',
            socioId: socio.id,
            cuenta: cuentaActual.numero,
            tipoCuenta: cuentaActual.tipo,
            formaPago,
            observacion,
        });

        setShowRecibo({ tipo, monto: m, cuenta: cuentaActual, socio, formaPago });
        setMonto('');
        setObservacion('');
    };

    const handleDeposito = () => {
        if (formaPago === 'efectivo') setShowDesglose(true);
        else setShowMixto(true);
    };

    const handleRetiro = () => ejecutarTransaccion('retiro');

    const onDesgloseConfirm = () => { setShowDesglose(false); ejecutarTransaccion('deposito'); };
    const onMixtoConfirm = () => { setShowMixto(false); ejecutarTransaccion('deposito'); };

    // ── Estilo de botón acción ────────────────────────────────────────────
    const btnNav = (onClick, icon, disabled = false) => (
        <button onClick={onClick} disabled={disabled}
            style={{ width: '36px', height: '36px', borderRadius: '8px', background: disabled ? 'rgba(37,99,235,0.3)' : 'var(--primary)', border: 'none', cursor: disabled ? 'default' : 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', transition: 'all 0.15s' }}>
            {icon}
        </button>
    );

    return (
        <div className="animate-up" style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
            {/* ── Título ── */}
            <div>
                <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Pagos en Caja</h1>
                <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Gestión de depósitos, retiros y transacciones de cuentas de socios</p>
            </div>

            {/* ════════════════════════════════════
                PANEL SUPERIOR: Búsqueda del Socio
            ════════════════════════════════════ */}
            <div className="card glass" style={{ padding: '1.25rem' }}>
                {/* Controles de búsqueda + navegación */}
                <div style={{ display: 'flex', alignItems: 'flex-end', gap: '0.75rem', flexWrap: 'wrap', marginBottom: socio ? '1rem' : 0 }}>
                    {[
                        ['Código', busqCodigo, setBusqCodigo],
                        ['Nombre', busqNombre, setBusqNombre],
                        ['Cédula', busqCedula, setBusqCedula],
                    ].map(([lbl, val, set]) => (
                        <div key={lbl} style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
                            <label style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>{lbl}</label>
                            <input type="text" className="input-field"
                                style={{ height: '2.1rem', fontSize: '0.85rem', width: lbl === 'Nombre' ? '220px' : '130px' }}
                                value={val} onChange={e => set(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleBuscar()} />
                        </div>
                    ))}
                    <button className="btn btn-primary" style={{ height: '2.1rem', gap: '0.4rem', fontSize: '0.85rem' }} onClick={handleBuscar}>
                        <Search size={15} /> Buscar
                    </button>
                    <button className="btn btn-secondary" style={{ height: '2.1rem', gap: '0.4rem', fontSize: '0.85rem' }} onClick={handleLimpiar}>
                        <RefreshCw size={14} /> Limpiar
                    </button>

                    {/* Navegación ◁ ▷ */}
                    {searched && filtrados.length > 0 && (
                        <div style={{ display: 'flex', gap: '0.35rem', marginLeft: 'auto' }}>
                            {btnNav(handlePrev, <ChevronLeft size={18} />, socioIdx === 0)}
                            {btnNav(handleNext, <ChevronRight size={18} />, socioIdx >= filtrados.length - 1)}
                            {btnNav(() => setSearched(false), <RefreshCw size={15} />)}
                            {btnNav(handleLimpiar, <X size={15} />)}
                            <span style={{ display: 'flex', alignItems: 'center', fontSize: '0.78rem', color: 'var(--text-muted)', paddingLeft: '0.25rem' }}>
                                {socioIdx + 1} / {filtrados.length}
                            </span>
                        </div>
                    )}
                </div>

                {/* Tarjeta datos del socio */}
                {socio && (
                    <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', gap: '1rem', padding: '1rem', background: 'linear-gradient(135deg, rgba(37,99,235,0.06), rgba(30,64,175,0.03))', borderRadius: 'var(--radius-md)', border: '1px solid rgba(37,99,235,0.15)' }}>
                        {/* Avatar */}
                        <div style={{ width: '64px', height: '64px', borderRadius: '50%', border: '3px solid var(--primary)', overflow: 'hidden', background: 'var(--primary-light)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                            {socio.foto
                                ? <img src={socio.foto} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                : <span style={{ fontSize: '1.75rem' }}>🧑</span>}
                        </div>

                        {/* Info */}
                        <div style={{ display: 'grid', gridTemplateColumns: '120px 1fr 120px 1fr', gap: '0.5rem 1rem' }}>
                            {[
                                ['Código', socio.codigo],
                                ['Nombre', socio.nombre],
                                ['Cédula', socio.cedula],
                                ['Estado', socio.condicion || socio.estado],
                                ['Dirección', socio.direccion, true],
                            ].map(([lbl, val, full]) => (
                                <div key={lbl} style={{ gridColumn: full ? 'span 3' : undefined }}>
                                    <div style={{ fontSize: '0.68rem', fontWeight: 700, color: 'var(--primary)', textTransform: 'uppercase', marginBottom: '0.1rem' }}>{lbl}</div>
                                    <div style={{ fontSize: '0.88rem', fontWeight: 600, color: 'var(--text)' }}>{val || '—'}</div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {searched && filtrados.length === 0 && (
                    <div style={{ padding: '1.5rem', textAlign: 'center', color: 'var(--text-muted)', fontSize: '0.9rem' }}>
                        No se encontraron socios con los criterios ingresados.
                    </div>
                )}
            </div>

            {/* ════════════════════════════════════
                CUENTAS ACTIVAS
            ════════════════════════════════════ */}
            {socio && (
                <div className="card glass" style={{ padding: '1.25rem' }}>
                    <h3 style={{ textAlign: 'center', fontSize: '1rem', fontWeight: 800, color: 'var(--primary)', marginBottom: '0.75rem', textTransform: 'uppercase', letterSpacing: '1px' }}>
                        Cuentas Activas
                    </h3>

                    <div style={{ border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', overflow: 'hidden' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '90px 1fr 160px 110px 1fr', background: 'var(--primary)', padding: '0.45rem 0.75rem', gap: '0.5rem' }}>
                            {['Número Cta.', 'Descripción', 'Tipo de Cuenta', 'Balance', 'Observación'].map(h => (
                                <span key={h} style={{ color: 'white', fontSize: '0.72rem', fontWeight: 800, textTransform: 'uppercase' }}>{h}</span>
                            ))}
                        </div>
                        {cuentas.map(ct => (
                            <div key={ct.id}
                                onClick={() => { setCuentaSel(ct); setMonto(''); setObservacion(''); }}
                                style={{
                                    display: 'grid', gridTemplateColumns: '90px 1fr 160px 110px 1fr',
                                    padding: '0.5rem 0.75rem', gap: '0.5rem',
                                    background: cuentaSel?.id === ct.id ? 'linear-gradient(90deg, var(--primary), #1e40af)' : 'var(--bg-card)',
                                    cursor: 'pointer', borderBottom: '1px solid var(--border-light)',
                                    transition: 'background 0.15s',
                                }}
                            >
                                <span style={{ fontSize: '0.85rem', fontWeight: 700, color: cuentaSel?.id === ct.id ? 'white' : 'var(--primary)' }}>{ct.numero}</span>
                                <span style={{ fontSize: '0.85rem', fontWeight: 600, color: cuentaSel?.id === ct.id ? 'white' : 'var(--text)' }}>{ct.descripcion}</span>
                                <span style={{ fontSize: '0.82rem', color: cuentaSel?.id === ct.id ? 'rgba(255,255,255,0.85)' : 'var(--text-muted)' }}>{ct.tipo}</span>
                                <span style={{ fontSize: '0.88rem', fontWeight: 700, color: cuentaSel?.id === ct.id ? 'white' : 'var(--success)', textAlign: 'right' }}>{fmt(ct.balance)}</span>
                                <span style={{ fontSize: '0.8rem', color: cuentaSel?.id === ct.id ? 'rgba(255,255,255,0.7)' : 'var(--text-muted)' }}>{ct.obs}</span>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* ════════════════════════════════════
                PANEL TRANSACCIÓN
            ════════════════════════════════════ */}
            {socio && cuentaSel && (
                <div className="card glass" style={{ padding: '1.25rem' }}>
                    <h3 style={{ textAlign: 'center', fontSize: '0.95rem', fontWeight: 800, color: 'var(--primary)', marginBottom: '1rem', textTransform: 'uppercase' }}>
                        Cuenta No. {cuentaActual?.numero} — {cuentaActual?.descripcion}
                    </h3>

                    {cuentaActual?.tipo === 'Préstamos' ? (
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 200px', gap: '1.5rem', alignItems: 'start' }}>
                            {/* Col 1: Saldos */}
                            <div style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', padding: '0.75rem' }}>
                                <div style={{ background: 'var(--primary)', color: 'white', padding: '0.4rem 0.75rem', fontSize: '0.72rem', fontWeight: 800, textTransform: 'uppercase', borderRadius: '4px 4px 0 0', margin: '-0.75rem -0.75rem 0.5rem -0.75rem' }}>Saldos de la Cuenta</div>
                                {[
                                    ['Cap. Atrasado', 0], ['Int. Atrasado', 0], ['Mora', 0], ['Seguro', 0], ['Comision', 0], ['Cuotas Atrasadas', 0]
                                ].map(([lbl, val]) => (
                                    <div key={lbl} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                        <span style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{lbl}</span>
                                        <div style={{ background: 'white', border: '1px solid var(--border)', borderRadius: '4px', width: '100px', padding: '0.2rem 0.4rem', fontSize: '0.8rem', textAlign: 'right', fontWeight: 700 }}>{fmt(val)}</div>
                                    </div>
                                ))}
                                <div style={{ borderTop: '1px solid var(--border)', marginTop: '0.5rem', paddingTop: '0.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: '0.85rem', fontWeight: 800 }}>Total en Atraso:</span>
                                    <span style={{ fontSize: '0.9rem', fontWeight: 800 }}>{fmt(0)}</span>
                                </div>
                            </div>

                            {/* Col 2: Inputs Préstamo */}
                            <div style={{ display: 'grid', gridTemplateColumns: '100px 1fr', gap: '0.4rem', alignItems: 'center' }}>
                                {['Capital', 'Interés', 'Mora', 'Seguro', 'Comisión', 'Otros'].map(lbl => (
                                    <React.Fragment key={lbl}>
                                        <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text)' }}>{lbl}</span>
                                        <input type="number" className="input-field" style={{ height: '2rem', textAlign: 'right', fontWeight: 700 }}
                                            value={loanFields[lbl.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "")]}
                                            onChange={e => setLoanFields({ ...loanFields, [lbl.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "")]: Number(e.target.value) })}
                                        />
                                    </React.Fragment>
                                ))}
                                <div style={{ gridColumn: 'span 2', display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                        <input type="checkbox" checked={muestraBalance} onChange={e => setMuestraBalance(e.target.checked)} /> Muestra Balance
                                    </label>
                                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                        <input type="checkbox" checked={saldarPrestamo} onChange={e => setSaldarPrestamo(e.target.checked)} /> Saldar el Préstamo
                                    </label>
                                </div>
                                <div style={{ gridColumn: 'span 2', marginTop: '0.5rem' }}>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)' }}>OBSERVACIONES</label>
                                    <textarea className="input-field" style={{ height: '3.5rem', marginTop: '0.2rem' }} value={observacion} onChange={e => setObservacion(e.target.value)} />
                                </div>
                                <div style={{ gridColumn: 'span 2', borderTop: '1px solid var(--border)', paddingTop: '0.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: '0.85rem', fontWeight: 800 }}>Monto a Aplicar</span>
                                    <span style={{ fontSize: '1.2rem', fontWeight: 900, color: 'var(--primary)' }}>{fmt(Object.values(loanFields).reduce((a, b) => a + b, 0))}</span>
                                </div>
                            </div>

                            {/* Col 3: NCF & Tipo Pago */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                <div>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)' }}>NCF</label>
                                    <select className="input-field" style={{ height: '2rem', fontSize: '0.8rem' }} value={ncf} onChange={e => setNcf(e.target.value)}>
                                        <option>(B02) Factura Consumidor Final</option>
                                        <option>(B01) Factura Crédito Fiscal</option>
                                    </select>
                                </div>
                                <div>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)' }}>TIPO DE PAGO</label>
                                    <div style={{ display: 'flex', border: '1px solid var(--border)', borderRadius: '6px', overflow: 'hidden', height: '2.5rem' }}>
                                        <button onClick={() => setTipoPago('pagar')} style={{ flex: 1, border: 'none', background: tipoPago === 'pagar' ? 'var(--primary)' : 'white', color: tipoPago === 'pagar' ? 'white' : 'var(--text)', fontWeight: 700, cursor: 'pointer' }}>Pagar</button>
                                        <button onClick={() => setTipoPago('abonar')} style={{ flex: 1, border: 'none', borderLeft: '1px solid var(--border)', background: tipoPago === 'abonar' ? 'var(--primary)' : 'white', color: tipoPago === 'abonar' ? 'white' : 'var(--text)', fontWeight: 700, cursor: 'pointer' }}>Abonar</button>
                                    </div>
                                </div>
                            </div>

                            {/* Footer Buttons */}
                            <div style={{ gridColumn: 'span 3', borderTop: '2px solid var(--primary)', paddingTop: '0.75rem', display: 'flex', gap: '0.5rem' }}>
                                <button className="btn btn-secondary" style={{ padding: '0.6rem 1.5rem', gap: '0.5rem', fontWeight: 800 }} onClick={() => setCuentaSel(null)}>
                                    <ChevronLeft size={16} /> Retroceder
                                </button>
                                <button className="btn btn-primary" style={{ flex: 1, background: 'var(--primary)', borderColor: 'var(--primary)', fontSize: '1.1rem', fontWeight: 900, gap: '0.5rem' }} onClick={handleDeposito}>
                                    <DollarSign size={20} /> Pagar ({fmt(Object.values(loanFields).reduce((a, b) => a + b, 0))})
                                </button>
                                <button className="btn btn-secondary" style={{ padding: '0.6rem 1.5rem', gap: '0.5rem', fontWeight: 800 }} onClick={() => setShowCuotas(true)}>
                                    <List size={16} /> Cuotas
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr auto', gap: '1.5rem', alignItems: 'start' }}>

                            {/* Saldos */}
                            <div style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', padding: '0.75rem', display: 'flex', flexDirection: 'column', gap: '0.3rem' }}>
                                <div style={{ fontSize: '0.72rem', fontWeight: 800, color: 'var(--primary)', textTransform: 'uppercase', borderBottom: '1px solid var(--border)', paddingBottom: '0.3rem', marginBottom: '0.25rem' }}>Saldos de la Cuenta</div>
                                {[
                                    ['Saldo Actual', saldoActual, 'var(--primary)'],
                                    ['Pignorado', pignorado, null],
                                    ['Flotante', flotante, null],
                                    ['Embargos', embargos, null],
                                ].map(([lbl, val, color]) => (
                                    <div key={lbl} style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.82rem' }}>
                                        <span style={{ color: 'var(--text-muted)', fontWeight: 500 }}>{lbl}</span>
                                        <span style={{ fontWeight: 700, color: color || 'inherit' }}>{fmt(val)}</span>
                                    </div>
                                ))}
                                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.88rem', borderTop: '2px solid var(--primary)', paddingTop: '0.35rem', marginTop: '0.25rem' }}>
                                    <span style={{ fontWeight: 700, color: 'var(--primary)' }}>Disponible</span>
                                    <span style={{ fontWeight: 800, color: 'var(--success)' }}>{fmt(disponible)}</span>
                                </div>
                            </div>

                            {/* Monto + Observación */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                <div>
                                    <label style={{ fontSize: '0.78rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.35rem', display: 'block' }}>Monto</label>
                                    <input type="number" min="0" className="input-field"
                                        style={{ fontSize: '1.4rem', fontWeight: 700, height: '3rem', padding: '0 0.75rem', color: 'var(--primary)', maxWidth: '260px', textAlign: 'right' }}
                                        value={monto} onChange={e => setMonto(e.target.value)}
                                        placeholder="0.00" />
                                </div>
                                <div>
                                    <label style={{ fontSize: '0.78rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.35rem', display: 'block' }}>Observación</label>
                                    <textarea className="input-field" style={{ height: '4rem', fontSize: '0.85rem', padding: '0.4rem 0.5rem', resize: 'none', maxWidth: '360px' }}
                                        value={observacion} onChange={e => setObservacion(e.target.value)} />
                                </div>

                                {/* Botones acción */}
                                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginTop: '0.25rem' }}>
                                    <button className="btn btn-secondary" style={{ gap: '0.4rem', fontSize: '0.85rem' }} onClick={() => setCuentaSel(null)}>
                                        <ChevronLeft size={15} /> Retroceder
                                    </button>
                                    <button className="btn btn-primary" style={{ gap: '0.4rem', fontSize: '0.85rem', background: 'var(--success)', borderColor: 'var(--success)', flex: 1 }} onClick={handleDeposito}>
                                        <DollarSign size={15} /> Depósito
                                    </button>
                                    <button className="btn btn-primary" style={{ gap: '0.4rem', fontSize: '0.85rem', background: 'var(--danger)', borderColor: 'var(--danger)', flex: 1 }} onClick={handleRetiro}>
                                        <ArrowUpCircle size={15} /> Retiro
                                    </button>
                                </div>
                            </div>

                            {/* Forma de Pago + Muestra Balance */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.82rem', fontWeight: 600, cursor: 'pointer' }}>
                                    <input type="checkbox" checked={muestraBalance} onChange={e => setMuestraBalance(e.target.checked)}
                                        style={{ width: '16px', height: '16px', accentColor: 'var(--primary)' }} />
                                    Muestra Balance
                                </label>
                                <div style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', padding: '0.75rem' }}>
                                    <div style={{ fontSize: '0.72rem', fontWeight: 800, color: 'var(--primary)', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Forma de Pago</div>
                                    {[['efectivo', 'Efectivo'], ['mixto', 'Pago Mixto']].map(([val, lbl]) => (
                                        <label key={val} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem', marginBottom: '0.35rem', cursor: 'pointer' }}>
                                            <input type="radio" name="formaPago" value={val} checked={formaPago === val} onChange={() => setFormaPago(val)}
                                                style={{ accentColor: 'var(--primary)', width: '15px', height: '15px' }} />
                                            {lbl}
                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* ── Modales ──────────────────────────────────────────────────────── */}
            {showCuotas && (
                <CuotasPendientesModal
                    cuotas={[
                        { id: 1, fecha: '09/03/2026', capital: 0.59, interes: 0.00, mora: 0, seguro: 0, otros: 0, total: 0.59 },
                        { id: 2, fecha: '08/04/2026', capital: 4956.37, interes: 544.43, mora: 0, seguro: 21.05, otros: 0, total: 5521.85 },
                        { id: 3, fecha: '08/05/2026', capital: 5030.71, interes: 470.09, mora: 0, seguro: 21.05, otros: 0, total: 5521.85 },
                    ]}
                    onConfirm={(totals) => {
                        setLoanFields({
                            capital: totals.capital,
                            interes: totals.interes,
                            mora: totals.mora,
                            seguro: totals.seguro,
                            comision: 0,
                            otros: totals.otros
                        });
                        setShowCuotas(false);
                    }}
                    onClose={() => setShowCuotas(false)}
                />
            )}
            {showDesglose && (
                <DesgloseModal
                    monto={parseFloat(monto) || 0}
                    onConfirm={onDesgloseConfirm}
                    onClose={() => setShowDesglose(false)}
                />
            )}
            {showMixto && (
                <PagosMixtosModal
                    monto={parseFloat(monto) || 0}
                    onConfirm={onMixtoConfirm}
                    onClose={() => setShowMixto(false)}
                />
            )}

            {/* Recibo de confirmación */}
            {showRecibo && (
                <div className="modal-overlay" style={{ zIndex: 1200 }}>
                    <div className="card glass" style={{ maxWidth: '380px', width: '100%', padding: '2rem', textAlign: 'center' }}>
                        <div style={{ width: '60px', height: '60px', borderRadius: '50%', background: showRecibo.tipo === 'deposito' ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1rem' }}>
                            {showRecibo.tipo === 'deposito' ? <ArrowDownCircle size={28} color="var(--success)" /> : <ArrowUpCircle size={28} color="var(--danger)" />}
                        </div>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 800, marginBottom: '0.5rem', color: showRecibo.tipo === 'deposito' ? 'var(--success)' : 'var(--danger)' }}>
                            {showRecibo.tipo === 'deposito' ? 'Depósito Exitoso' : 'Retiro Exitoso'}
                        </h2>
                        <p style={{ color: 'var(--text-muted)', marginBottom: '1rem', fontSize: '0.9rem' }}>
                            {showRecibo.socio.nombre}<br />
                            <strong>{showRecibo.cuenta.descripcion}</strong>
                        </p>
                        <div style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--primary)', marginBottom: '1.5rem' }}>
                            RD$ {fmt(showRecibo.monto)}
                        </div>
                        <div style={{ display: 'flex', gap: '0.75rem' }}>
                            <button className="btn btn-secondary" style={{ flex: 1, gap: '0.4rem' }} onClick={() => setShowRecibo(null)}>
                                <X size={14} /> Cerrar
                            </button>
                            <button className="btn btn-primary" style={{ flex: 1, gap: '0.4rem' }} onClick={() => { window.print(); setShowRecibo(null); }}>
                                <Printer size={14} /> Imprimir
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default PagosEnCaja;

import React, { useState } from 'react';
import { useAhorros } from '../context/AhorrosContext';
import { Calculator, CalendarHeart, RefreshCw, CheckCircle, Clock, Save, FileText } from 'lucide-react';

const TABS = [
    { id: 'interes-certificado', label: 'Cálculo Interés Certificado', icon: FileText },
    { id: 'interes-ahorros', label: 'Cálculo Interés Ahorros', icon: Calculator },
];

const Procesos = () => {
    const { cuentas, calcularIntereses } = useAhorros();
    const [activeTab, setActiveTab] = useState('interes-ahorros');
    const [procesando, setProcesando] = useState(false);
    const [resultado, setResultado] = useState(null);

    const formatMoney = v => new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(Number(v) || 0);

    const handleProcesar = () => {
        setProcesando(true);
        setTimeout(() => {
            const result = calcularIntereses(); // Función de AhorrosContext para simular capitalización
            setResultado({
                fecha: new Date().toLocaleString(),
                tipo: activeTab === 'interes-ahorros' ? 'Ahorro Retirable' : 'Certificados/Plazos Fijos',
                cuentasAfectadas: activeTab === 'interes-ahorros' ? cuentas.filter(c => c.tipo === 'Ahorro Retirable').length : cuentas.filter(c => c.tipo === 'Plazo Fijo').length,
                montoCalculado: result
            });
            setProcesando(false);
            alert('✅ Proceso de cálculo y capitalización de intereses completado con éxito.');
        }, 2000);
    };

    return (
        <div className="animate-up" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Procesos y Cierres</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Módulo de ejecución de procesos automáticos, cierres de mes y cálculos de intereses.</p>
                </div>
            </div>

            {/* Ribbon-like Tabs */}
            <div className="card" style={{ padding: '0.5rem', marginBottom: '1.5rem', display: 'flex', gap: '0.5rem', overflowX: 'auto', whiteSpace: 'nowrap' }}>
                {TABS.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => { setActiveTab(tab.id); setResultado(null); }}
                            style={{
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.75rem 1.25rem',
                                border: 'none',
                                background: isActive ? 'var(--primary-light)' : 'transparent',
                                color: isActive ? 'var(--primary)' : 'var(--text-muted)',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                minWidth: '150px'
                            }}
                        >
                            <Icon size={24} strokeWidth={isActive ? 2.5 : 1.5} />
                            <span style={{ fontSize: '0.75rem', fontWeight: isActive ? 700 : 500 }}>
                                {tab.label}
                            </span>
                        </button>
                    );
                })}
            </div>

            {/* Tab Contents */}
            <div className="card" style={{ flex: 1, padding: '2rem' }}>
                <div style={{ display: 'grid', gridTemplateColumns: 'minmax(400px, 1fr) 2fr', gap: '2rem' }}>
                    <div className="animate-fade-in" style={{ borderRight: '1px solid var(--border)', paddingRight: '2rem' }}>
                        <h3 style={{ marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            {activeTab === 'interes-ahorros' ? <Calculator size={20} className="text-primary" /> : <FileText size={20} className="text-primary" />}
                            {activeTab === 'interes-ahorros' ? 'Capitalización de Ahorros' : 'Capitalización de Certificados'}
                        </h3>

                        <p style={{ color: 'var(--text-muted)', marginBottom: '2rem', fontSize: '0.85rem' }}>
                            {activeTab === 'interes-ahorros'
                                ? 'Este proceso calculará los intereses generados sobre el balance promedio diario de las cuentas de Ahorro Retirable y capitalizará el monto a la cuenta del socio.'
                                : 'Este proceso genera el cálculo de rendimiento para los Certificados de Inversión y Plazos Fijos vigentes en el período seleccionado, transfiriendo los intereses a cuentas de ahorros según orden de pago.'}
                        </p>

                        <div className="input-group" style={{ marginBottom: '1.5rem' }}>
                            <label className="input-label">Período de Aplicación</label>
                            <input type="month" className="input-field" defaultValue="2026-03" />
                        </div>

                        <div className="input-group" style={{ marginBottom: '2.5rem' }}>
                            <label className="input-label">Tipo de Cambio / Modalidad</label>
                            <select className="input-field">
                                <option>Tasa Fija General</option>
                                <option>Tasas Variables por Escala</option>
                            </select>
                        </div>

                        <button
                            className="btn btn-primary"
                            style={{ width: '100%', height: '50px', fontSize: '1rem' }}
                            onClick={handleProcesar}
                            disabled={procesando}
                        >
                            <RefreshCw size={20} className={procesando ? 'spin' : ''} />
                            {procesando ? 'Procesando Cartera...' : 'Ejecutar Cálculo Masivo'}
                        </button>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center' }}>
                        {procesando ? (
                            <div className="animate-fade-in" style={{ textAlign: 'center', color: 'var(--primary)' }}>
                                <RefreshCw size={48} className="spin" style={{ opacity: 0.5, marginBottom: '1rem' }} />
                                <h3 style={{ fontSize: '1.25rem' }}>Procesando {cuentas.length} cuentas...</h3>
                                <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>Aplicando fórmulas de interés compuesto / simple.</p>
                            </div>
                        ) : resultado ? (
                            <div className="animate-fade-in" style={{ background: 'rgba(16, 185, 129, 0.05)', border: '1px solid rgba(16, 185, 129, 0.2)', padding: '2.5rem', borderRadius: '16px', textAlign: 'center', width: '100%', maxWidth: '400px' }}>
                                <CheckCircle size={56} style={{ color: 'var(--success)', marginBottom: '1rem' }} />
                                <h2 style={{ color: 'var(--success)', marginBottom: '0.5rem', fontSize: '1.5rem' }}>Proceso Exitoso</h2>
                                <div style={{ fontWeight: 700, fontSize: '0.85rem', marginBottom: '1.5rem', color: 'var(--text-muted)' }}>ID: PROC-{Date.now().toString().slice(-6)}</div>

                                <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '0.75rem', textAlign: 'left', background: 'var(--background)', padding: '1.5rem', borderRadius: '8px' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Tipo:</span>
                                        <span style={{ fontWeight: 600, fontSize: '0.85rem' }}>{resultado.tipo}</span>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Cuentas Impactadas:</span>
                                        <span style={{ fontWeight: 600, fontSize: '0.85rem' }}>{resultado.cuentasAfectadas} expedientes</span>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', borderTop: '1px solid var(--border)', paddingTop: '0.75rem', marginTop: '0.25rem' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Total Distribuido:</span>
                                        <span style={{ fontWeight: 800, color: 'var(--primary)', fontSize: '1rem' }}>{formatMoney(resultado.montoCalculado)}</span>
                                    </div>
                                </div>

                                <button className="btn btn-secondary" style={{ marginTop: '1.5rem', width: '100%' }}>
                                    <Save size={16} /> Descargar Informe de Contabilidad
                                </button>
                            </div>
                        ) : (
                            <div className="animate-fade-in" style={{ textAlign: 'center', opacity: 0.3, padding: '4rem' }}>
                                <CalendarHeart size={84} style={{ marginBottom: '1rem' }} />
                                <h3 style={{ fontSize: '1.25rem' }}>Resultados del Proceso</h3>
                                <p>Configura los parámetros a la izquierda y presiona el botón para ejecutar el cierre de intereses.</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Procesos;

