};

export default Reportes;

import React, { useState } from 'react';
import { useSegmentacion } from '../context/SegmentacionContext';
import {
    Users, Map, Globe, Flag, MapPin, Navigation,
    Share2, Activity, UserMinus, Briefcase, Coins,
    UserCheck, GraduationCap, Gavel, BarChart2
} from 'lucide-react';
import { ResponsiveContainer, PieChart, Pie, Cell, Tooltip } from 'recharts';

const TABS = [
    { id: 'dashboard', label: 'Dashboard Analítico', icon: BarChart2 },
    { id: 'areas', label: 'Áreas', icon: Share2 },
    { id: 'paises', label: 'Países', icon: Globe },
    { id: 'ciudades', label: 'Ciudades', icon: MapPin },
    { id: 'regiones', label: 'Regiones', icon: Map },
    { id: 'sectores', label: 'Sectores', icon: Navigation },
    { id: 'distritos', label: 'Distritos', icon: Flag },
    { id: 'condicion', label: 'Cond. Socio', icon: Users },
    { id: 'seguimiento', label: 'Est. Seguimiento', icon: Activity },
    { id: 'desafiliacion', label: 'Mot. Desafiliación', icon: UserMinus },
    { id: 'fondos', label: 'Fondos', icon: Briefcase },
    { id: 'monedas', label: 'Monedas', icon: Coins },
    { id: 'oficiales', label: 'Oficiales', icon: UserCheck },
    { id: 'profesiones', label: 'Profesiones', icon: GraduationCap },
    { id: 'abogados', label: 'Cobros Abogado', icon: Gavel },
];

const Segmentacion = () => {
    const { segmentos, sociosSegmentados } = useSegmentacion();
    const [activeTab, setActiveTab] = useState('dashboard');

    const totalSocios = segmentos.reduce((acc, s) => acc + (s.totalSocios || 0), 0);
    const SEG_COLORS = ['#6366f1', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444'];
    const pieData = segmentos.map((s, i) => ({ name: s.nombre, value: s.totalSocios, color: SEG_COLORS[i] || '#64748b' }));

    const renderEmptyCatalog = (title, description) => (
        <div className="animate-fade-in" style={{ padding: '2rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h3 style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', margin: 0 }}>
                    {TABS.find(t => t.id === activeTab)?.icon({ size: 24, className: 'text-primary' })}
                    Mantenimiento de {title}
                </h3>
                <button className="btn btn-primary">Añadir Nuevo</button>
            </div>
            <p style={{ color: 'var(--text-muted)', marginBottom: '2rem' }}>{description}</p>

            <div style={{ border: '1px dashed var(--border)', borderRadius: '12px', padding: '4rem', textAlign: 'center', background: '#f8fafc' }}>
                <p style={{ color: 'var(--text-muted)', margin: 0 }}>Catálogo de <strong>{title}</strong> actualmente vacío u operando con datos por defecto.</p>
            </div>
        </div>
    );

    return (
        <div className="animate-up" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem' }}>Segmentación y Parámetros</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Configuración de catálogos y análisis de cartera de socios</p>
                </div>
            </div>

            {/* Ribbon-like Tabs */}
            <div className="card" style={{ padding: '0.5rem', marginBottom: '1.5rem', display: 'flex', gap: '0.5rem', overflowX: 'auto', whiteSpace: 'nowrap' }}>
                {TABS.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            style={{
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.75rem 1rem',
                                border: 'none',
                                background: isActive ? 'var(--primary-light)' : 'transparent',
                                color: isActive ? 'var(--primary)' : 'var(--text-muted)',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                minWidth: '95px'
                            }}
                        >
                            <Icon size={22} strokeWidth={isActive ? 2.5 : 1.5} />
                            <span style={{ fontSize: '0.7rem', fontWeight: isActive ? 700 : 500 }}>
                                {tab.label}
                            </span>
                        </button>
                    );
                })}
            </div>

            {/* Tab Contents */}
            <div className="card" style={{ flex: 1, overflowY: 'auto', padding: activeTab === 'dashboard' ? '1.5rem' : 0 }}>
                {activeTab === 'dashboard' && (
                    <div className="animate-fade-in">
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '1rem', marginBottom: '2rem' }}>
                            {segmentos.map((seg, i) => (
                                <div key={seg.id} className="card" style={{ borderLeft: `4px solid ${SEG_COLORS[i]}`, background: 'var(--bg-card)', padding: '1.25rem' }}>
                                    <div style={{ fontSize: '1.75rem', fontWeight: 800, color: SEG_COLORS[i], marginBottom: '0.25rem' }}>{seg.totalSocios}</div>
                                    <div style={{ fontWeight: 700, fontSize: '0.85rem' }}>{seg.nombre}</div>
                                </div>
                            ))}
                        </div>
                        <div style={{ height: 300 }}>
                            <h3 style={{ fontWeight: 700, marginBottom: '1rem', fontSize: '1rem' }}>Distribución de Cartera Total ({totalSocios})</h3>
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={pieData} cx="50%" cy="50%" innerRadius={70} outerRadius={110} dataKey="value" label>
                                        {pieData.map((_, i) => <Cell key={i} fill={SEG_COLORS[i]} />)}
                                    </Pie>
                                    <Tooltip />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                )}

                {activeTab === 'areas' && renderEmptyCatalog('Áreas Geográficas / Negocio', 'Define las grandes áreas para agrupar sucursales y regiones.')}
                {activeTab === 'paises' && renderEmptyCatalog('Países', 'Gestión de países de residencia o nacionalidad de los socios.')}
                {activeTab === 'ciudades' && renderEmptyCatalog('Ciudades', 'Catálogo de provincias y ciudades principales.')}
                {activeTab === 'regiones' && renderEmptyCatalog('Regiones', 'Asignación de zonas (Norte, Sur, Este, Oeste).')}
                {activeTab === 'sectores' && renderEmptyCatalog('Sectores', 'Distribución de barrios y sectores urbanos/rurales.')}
                {activeTab === 'distritos' && renderEmptyCatalog('Distritos', 'Divisiones administrativas menores.')}
                {activeTab === 'condicion' && renderEmptyCatalog('Condición del Socio', 'Tipificación de estados (Activo, Funcionario, Empleado, Especial).')}
                {activeTab === 'seguimiento' && renderEmptyCatalog('Estados de Seguimiento', 'Fases de los procesos jurídicos o de cobro.')}
                {activeTab === 'desafiliacion' && renderEmptyCatalog('Motivos de Desafiliación', 'Estadísticas de por qué los socios salen de la cooperativa.')}
                {activeTab === 'fondos' && renderEmptyCatalog('Fondos de Origen', 'Procedencia de los recursos crediticios.')}
                {activeTab === 'monedas' && renderEmptyCatalog('Monedas', 'Tipos de cambio y divisas soportadas (DOP, USD, EUR).')}
                {activeTab === 'oficiales' && renderEmptyCatalog('Oficiales de Cuenta', 'Asesores de crédito/negocios asignados a socios.')}
                {activeTab === 'profesiones' && renderEmptyCatalog('Profesiones y Oficios', 'Catálogo utilizado para la matriz de riesgos AML/CFT.')}
                {activeTab === 'abogados' && renderEmptyCatalog('Tarifas de Cobro Legal', 'Listado de bufetes y costos por etapa de demanda.')}
            </div>
        </div>
    );
};

export default Segmentacion;

import React, { useState } from 'react';
import { useSocios, getDefaultSocio } from '../context/SociosContext';
import { Search, User, List, Database, Image, Activity, Plus, Save, Trash2, ArrowLeft, Wallet } from 'lucide-react';
import TabBuscar from './socios/TabBuscar';
import TabGenerales from './socios/TabGenerales';
import TabGestion from './socios/TabGestion';
import TabReferencias from './socios/TabReferencias';
import TabFotos from './socios/TabFotos';
import TabSeguimiento from './socios/TabSeguimiento';
import TabHistorial from './socios/TabHistorial';
import { useAhorros } from '../context/AhorrosContext';
import { usePrestamos } from '../context/PrestamosContext';

// ── Tab config ──────────────────────────────────────────────────────────────
const TABS = [
    { id: 'buscar', label: 'Buscar', icon: Search },
    { id: 'generales', label: 'Generales', icon: User },
    { id: 'gestion', label: 'Gestión', icon: List },
    { id: 'referencias', label: 'Referencias', icon: Database },
    { id: 'fotos', label: 'Fotos | Firmas', icon: Image },
    { id: 'seguimiento', label: 'Seguimiento', icon: Activity },
    { id: 'historial', label: 'Historial', icon: Wallet },
];

const Socios = () => {
    const {
        socios, agregarSocio, actualizarSocio, eliminarSocio,
        agregarInmueble, eliminarInmueble,
        agregarVehiculo, eliminarVehiculo,
        agregarReferencia, eliminarReferencia,
        agregarDependiente, eliminarDependiente,
        agregarBeneficiario, eliminarBeneficiario,
        agregarCaso, eliminarCaso
    } = useSocios();

    const [tab, setTab] = useState('buscar');
    const [selectedSocio, setSelectedSocio] = useState(null);
    const [editData, setEditData] = useState(null); // datos editables
    const [isNew, setIsNew] = useState(false);
    const [showConfirmDel, setShowConfirmDel] = useState(false);

    // ── Seleccionar socio desde tabla de buscar ───────────────────────────
    const handleSelectSocio = (socio) => {
        setSelectedSocio(socio);
        setEditData({ ...socio });
        setIsNew(false);
        setTab('generales');
    };

    // ── Nuevo socio ────────────────────────────────────────────────────────
    const handleNuevo = () => {
        const blank = getDefaultSocio();
        setSelectedSocio(null);
        setEditData(blank);
        setIsNew(true);
        setTab('generales');
    };

    // ── Cambio de campo en el formulario ──────────────────────────────────
    const handleChange = (field, value) => {
        setEditData(prev => ({ ...prev, [field]: value }));
    };

    // ── Guardar ───────────────────────────────────────────────────────────
    const handleGuardar = () => {
        if (!editData.nombre?.trim()) {
            alert('El nombre del socio es obligatorio.');
            return;
        }
        if (isNew) {
            const nuevo = agregarSocio(editData);
            setSelectedSocio(nuevo);
            setEditData(nuevo);
            setIsNew(false);
        } else {
            actualizarSocio(selectedSocio.id, editData);
            const updated = { ...selectedSocio, ...editData };
            setSelectedSocio(updated);
        }
    };

    // ── Eliminar ──────────────────────────────────────────────────────────
    const handleEliminar = () => {
        eliminarSocio(selectedSocio.id);
        setSelectedSocio(null);
        setEditData(null);
        setIsNew(false);
        setTab('buscar');
        setShowConfirmDel(false);
    };

    const activeSocio = isNew ? null : selectedSocio;
    const fmtMoney = n => new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(Number(n) || 0);

    return (
        <div className="animate-up" style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
            {/* ── Header ── */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                <div>
                    <h1 className="page-title" style={{ marginBottom: '0.25rem', fontSize: '1.5rem' }}>Gestión de Socios</h1>
                    <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                        {socios.length} socio(s) registrado(s)
                        {selectedSocio && !isNew && (
                            <span style={{ marginLeft: '1rem', color: 'var(--primary)', fontWeight: 700 }}>
                                ▶ {selectedSocio.nombre}
                            </span>
                        )}
                        {isNew && <span style={{ marginLeft: '1rem', color: 'var(--success)', fontWeight: 700 }}>▶ Nuevo Socio</span>}
                    </p>
                </div>

                {/* Action buttons */}
                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                    <button className="btn btn-secondary" style={{ fontSize: '0.8rem', gap: '0.4rem' }} onClick={() => { setTab('buscar'); }}>
                        <ArrowLeft size={15} /> Volver al Listado
                    </button>
                    <button className="btn btn-primary" style={{ fontSize: '0.8rem', gap: '0.4rem' }} onClick={handleNuevo}>
                        <Plus size={15} /> Nuevo Socio
                    </button>
                    {(isNew || selectedSocio) && (
                        <button className="btn btn-primary" style={{ fontSize: '0.8rem', gap: '0.4rem', background: 'var(--success)', borderColor: 'var(--success)' }} onClick={handleGuardar}>
                            <Save size={15} /> {isNew ? 'Crear Socio' : 'Guardar Cambios'}
                        </button>
                    )}
                    {selectedSocio && !isNew && (
                        <button className="btn btn-secondary" style={{ fontSize: '0.8rem', gap: '0.4rem', color: 'var(--danger)', borderColor: 'rgba(239,68,68,0.2)' }}
                            onClick={() => setShowConfirmDel(true)}>
                            <Trash2 size={15} /> Eliminar
                        </button>
                    )}
                </div>
            </div>

            {/* ── KPI strip (cuando hay socio seleccionado) ── */}
            {selectedSocio && !isNew && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '0.75rem', marginBottom: '1rem' }}>
                    {[
                        { label: 'Ahorros', val: fmtMoney(selectedSocio.ahorros), color: 'var(--primary)', bg: 'var(--primary-light)' },
                        { label: 'Préstamos', val: fmtMoney(selectedSocio.prestamos), color: 'var(--danger)', bg: 'rgba(239,68,68,0.07)' },
                        { label: 'Aportaciones', val: fmtMoney(selectedSocio.aportacion), color: 'var(--success)', bg: 'rgba(16,185,129,0.07)' },
                        { label: 'Ingreso Mensual', val: fmtMoney(selectedSocio.ingresoMensual), color: 'var(--warning)', bg: 'rgba(245,158,11,0.07)' },
                    ].map(k => (
                        <div key={k.label} style={{ padding: '0.75rem 1rem', borderRadius: 'var(--radius-md)', background: k.bg, border: `1px solid ${k.color}22` }}>
                            <div style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>{k.label}</div>
                            <div style={{ fontSize: '1.1rem', fontWeight: 800, color: k.color }}>{k.val}</div>
                        </div>
                    ))}
                </div>
            )}

            {/* ── Tabs Navigation ── */}
            <div className="card glass" style={{ padding: 0, overflow: 'hidden' }}>
                {/* Tab bar */}
                <div style={{ display: 'flex', background: 'linear-gradient(135deg, var(--primary), #1e40af)', borderRadius: 'var(--radius-lg) var(--radius-lg) 0 0', overflowX: 'auto' }}>
                    {TABS.map(({ id, label, icon: Icon }) => {
                        const active = tab === id;
                        return (
                            <button key={id} onClick={() => setTab(id)}
                                style={{
                                    display: 'flex', alignItems: 'center', gap: '0.4rem',
                                    padding: '0.9rem 1.25rem', fontSize: '0.82rem',
                                    fontWeight: active ? 700 : 500,
                                    color: active ? 'var(--primary)' : 'rgba(255,255,255,0.8)',
                                    background: active ? 'white' : 'transparent',
                                    borderRadius: active ? 'var(--radius-md) var(--radius-md) 0 0' : 0,
                                    cursor: 'pointer', transition: 'all 0.2s',
                                    whiteSpace: 'nowrap', flexShrink: 0,
                                    marginTop: active ? '4px' : 0,
                                    boxShadow: active ? '0 -4px 12px rgba(0,0,0,0.08)' : 'none',
                                }}>
                                <Icon size={15} />
                                {label}
                            </button>
                        );
                    })}
                </div>

                {/* Tab Content */}
                <div style={{ padding: '1.5rem', overflowY: 'auto', maxHeight: 'calc(100vh - 360px)' }}>
                    {tab === 'buscar' && (
                        <TabBuscar socios={socios} onSelectSocio={handleSelectSocio} selectedId={selectedSocio?.id} />
                    )}
                    {tab === 'generales' && (
                        <TabGenerales datos={editData || getDefaultSocio()} onChange={handleChange} />
                    )}
                    {tab === 'gestion' && (
                        <TabGestion
                            socio={activeSocio}
                            onAgregarInmueble={agregarInmueble}
                            onEliminarInmueble={eliminarInmueble}
                            onAgregarVehiculo={agregarVehiculo}
                            onEliminarVehiculo={eliminarVehiculo}
                        />
                    )}
                    {tab === 'referencias' && (
                        <TabReferencias
                            socio={activeSocio}
                            onAgregarReferencia={agregarReferencia}
                            onEliminarReferencia={eliminarReferencia}
                            onAgregarDependiente={agregarDependiente}
                            onEliminarDependiente={eliminarDependiente}
                            onAgregarBeneficiario={agregarBeneficiario}
                            onEliminarBeneficiario={eliminarBeneficiario}
                        />
                    )}
                    {tab === 'fotos' && (
                        <TabFotos socio={activeSocio} onActualizar={actualizarSocio} />
                    )}
                    {tab === 'seguimiento' && (
                        <TabSeguimiento
                            socio={activeSocio}
                            onAgregarCaso={agregarCaso}
                            onEliminarCaso={eliminarCaso}
                        />
                    )}
                    {tab === 'historial' && (
                        <TabHistorial socioId={activeSocio?.id} />
                    )}
                </div>
            </div>

            {/* ── Confirm Delete Modal ── */}
            {showConfirmDel && (
                <div className="modal-overlay">
                    <div className="card glass" style={{ maxWidth: '420px', width: '100%', padding: '2rem', textAlign: 'center' }}>
                        <div style={{ width: '56px', height: '56px', background: 'rgba(239,68,68,0.1)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1rem' }}>
                            <Trash2 size={24} color="var(--danger)" />
                        </div>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '0.5rem' }}>Eliminar Socio</h2>
                        <p style={{ color: 'var(--text-muted)', marginBottom: '1.5rem' }}>¿Estás seguro de que deseas eliminar a <strong>{selectedSocio?.nombre}</strong>? Esta acción no se puede deshacer.</p>
                        <div style={{ display: 'flex', gap: '1rem' }}>
                            <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowConfirmDel(false)}>Cancelar</button>
                            <button className="btn btn-primary" style={{ flex: 1, background: 'var(--danger)', borderColor: 'var(--danger)' }} onClick={handleEliminar}>Sí, Eliminar</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Socios;

import React, { useState } from 'react';
import { useFacturacion } from '../context/FacturacionContext';
import { useCompras } from '../context/ComprasContext';
import { useContabilidad } from '../context/ContabilidadContext';
import { useCaja } from '../context/CajaContext';
import { CheckCircle, Clock, Receipt, Banknote } from 'lucide-react';

const Tesoreria = ({ tipo }) => {
    const { facturas, registrarPagoFactura } = useFacturacion();
    const { compras, registrarPagoCompra } = useCompras();
    const { registrarRecibo } = useCaja();

    const isIngreso = tipo === 'ingreso';
    const facturasPendientes = facturas.filter(f => f.condicion === 'Credito' && f.estado !== 'Pagada');
    const comprasPendientes = compras.filter(c => c.condicion === 'Credito' && c.estado !== 'Pagada');

    const [selectedId, setSelectedId] = useState('');
    const [success, setSuccess] = useState(false);
    const [lastReceipt, setLastReceipt] = useState(null);

    const handleLiquidar = (e) => {
        e.preventDefault();

        if (isIngreso) {
            const factura = facturas.find(f => f.id === selectedId);
            if (!factura) return;

            registrarPagoFactura(factura.id, factura.total);

            // Generar Recibo de Caja
            const recibo = registrarRecibo({
                cliente: factura.cliente?.nombre || factura.clienteNombre || 'Cliente General',
                monto: factura.total,
                concepto: `Pago de Factura ${factura.ncf || factura.numero}`,
                metodo: 'Efectivo/Transferencia'
            });
            setLastReceipt(recibo);
        } else {
            const compra = compras.find(c => c.id === selectedId);
            if (!compra) return;
            registrarPagoCompra(compra.id, compra.total);
        }

        setSuccess(true);
        setSelectedId('');
        setTimeout(() => setSuccess(false), 5000);
    };

    return (
        <div className="animate-up">
            <div style={{ marginBottom: '2rem' }}>
                <h1 className="page-title">{isIngreso ? 'Cobros a Clientes' : 'Pagos a Proveedores'}</h1>
                <p style={{ color: 'var(--text-muted)' }}>
                    {isIngreso
                        ? 'Registra la entrada de efectivo al liquidar facturas a crédito.'
                        : 'Registra la salida de fondos para saldar deudas con proveedores.'}
                </p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: success ? '1fr' : '1fr 1fr', gap: '2rem' }}>
                <div className="card" style={{ padding: '2rem' }}>
                    {success ? (
                        <div style={{ textAlign: 'center', padding: '1rem' }}>
                            <div style={{
                                width: '64px',
                                height: '64px',
                                borderRadius: '50%',
                                background: 'var(--success-light)',
                                color: 'var(--success)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                margin: '0 auto 1.5rem'
                            }}>
                                <CheckCircle size={32} />
                            </div>
                            <h2 style={{ marginBottom: '0.5rem' }}>Operación Exitosa</h2>
                            <p style={{ color: 'var(--text-muted)', marginBottom: '2rem' }}>
                                Se ha registrado el {isIngreso ? 'cobro' : 'pago'} y generado el asiento contable correspondiente.
                            </p>

                            {isIngreso && lastReceipt && (
                                <div className="card glass" style={{ textAlign: 'left', padding: '1.5rem', marginBottom: '2.5rem', border: '1px solid var(--success)' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                                        <span style={{ fontWeight: 700 }}>RECIBO {lastReceipt.numero}</span>
                                        <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{new Date(lastReceipt.fecha).toLocaleString()}</span>
                                    </div>
                                    <div style={{ fontSize: '0.9rem', marginBottom: '0.5rem' }}><b>Recibido de:</b> {lastReceipt.cliente}</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--success)', marginBottom: '0.5rem' }}>{new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(lastReceipt.monto)}</div>
                                    <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}><b>Concepto:</b> {lastReceipt.concepto}</div>
                                </div>
                            )}

                            <button className="btn btn-primary" onClick={() => { setSuccess(false); setLastReceipt(null); }}>
                                Registrar otro {isIngreso ? 'Cobro' : 'Pago'}
                            </button>
                        </div>
                    ) : (
                        <form onSubmit={handleLiquidar}>
                            <h3 style={{ marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                {isIngreso ? <Banknote color="var(--success)" /> : <Receipt color="var(--danger)" />}
                                Datos del {isIngreso ? 'Cobro' : 'Pago'}
                            </h3>

                            <div className="input-group">
                                <label className="input-label">Seleccionar {isIngreso ? 'Factura de Cliente' : 'Factura de Proveedor'}</label>
                                <select
                                    className="input-field"
                                    value={selectedId}
                                    onChange={e => setSelectedId(e.target.value)}
                                    required
                                    style={{ height: '3.5rem' }}
                                >
                                    <option value="">-- Seleccione un documento pendiente --</option>
                                    {(isIngreso ? facturasPendientes : comprasPendientes).map(doc => (
                                        <option key={doc.id} value={doc.id}>
                                            {doc.ncf || doc.numero} - {doc.cliente?.nombre || doc.proveedor?.nombre || doc.clienteNombre || 'Prov. Gen.'} ({new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(doc.total)})
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="input-group">
                                <label className="input-label">Método de Pago</label>
                                <select className="input-field" style={{ height: '3.5rem' }}>
                                    <option>Efectivo</option>
                                    <option>Transferencia Bancaria</option>
                                    <option>Cheque</option>
                                    <option>Tarjeta de Crédito</option>
                                </select>
                            </div>

                            <div className="input-group">
                                <label className="input-label">Comentario / Referencia</label>
                                <input className="input-field" placeholder="Ej: Transf. #12345" style={{ height: '3.5rem' }} />
                            </div>

                            <button type="submit" className="btn btn-primary" style={{ width: '100%', height: '3.5rem', marginTop: '1rem' }} disabled={!selectedId}>
                                {isIngreso ? 'Generar Recibo e Ingresar' : 'Procesar Pago a Proveedor'}
                            </button>
                        </form>
                    )}
                </div>

                {!success && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div className="card glass" style={{ padding: '1.5rem' }}>
                            <h4 style={{ marginBottom: '1rem', color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', fontWeight: 800 }}>Resumen de Cartera</h4>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                <span>Total Pendiente:</span>
                                <span style={{ fontWeight: 700, fontSize: '1.25rem', color: isIngreso ? 'var(--primary)' : 'var(--danger)' }}>
                                    {new Intl.NumberFormat('es-DO', { style: 'currency', currency: 'DOP' }).format(
                                        (isIngreso ? facturasPendientes : comprasPendientes).reduce((acc, d) => acc + d.total, 0)
                                    )}
                                </span>
                            </div>
                            <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>
                                {isIngreso
                                    ? `Tienes ${(isIngreso ? facturasPendientes : comprasPendientes).length} facturas esperando cobro.`
                                    : `Tienes ${(isIngreso ? facturasPendientes : comprasPendientes).length} facturas esperando pago.`}
                            </div>
                        </div>

                        <div className="card" style={{ padding: '1.5rem', background: 'var(--primary-light)', color: 'var(--primary)', border: 'none' }}>
                            <div style={{ display: 'flex', gap: '1rem', alignItems: 'flex-start' }}>
                                <Clock size={20} />
                                <div>
                                    <div style={{ fontWeight: 700, marginBottom: '0.25rem' }}>Recordatorio de Auditoría</div>
                                    <div style={{ fontSize: '0.8rem', opacity: 0.9 }}>
                                        Cada recibo generado queda registrado en el módulo de **Caja** para su posterior anulación o reporte de cierre.
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Tesoreria;

